import firebase from 'firebase/compat/app';
import { auth } from '../firebase';
import { UserStats } from '../types';
import { formatMinutes } from '../services/statsService';
import { X, User as UserIcon, Save, Key, AlertCircle, CheckCircle, Database, Camera, Loader2, Zap } from 'lucide-react';
import { CyberButton, CyberInput, CyberCard, GlitchText } from './CyberUI';

// Provided Vercel Blob Token
const VERCEL_BLOB_TOKEN = "vercel_blob_rw_VnUe4Ebpw4pk7Pjs_zVs3scmyC6SIj6xg6s87VZXp9vF8f1";

