                    </div>
                    <div className="text-[10px] font-mono text-gray-500 mt-1 uppercase tracking-tighter">UID: {user.uid.substring(0,8)}</div>
                </div>
            </div>

            <div className="flex-1 space-y-4">
                <div>
                   <label className="text-[10px] font-mono text-gray-500 uppercase tracking-widest">Designation</label>
                   <div className="text-white font-bold text-lg">{user.displayName || 'ANONYMOUS_RUNNER'}</div>
                </div>
                <div>
                   <label className="text-[10px] font-mono text-gray-500 uppercase tracking-widest">Uplink Address</label>
                   <div className="text-gray-300 font-mono text-sm">{user.email}</div>
                </div>
                <div>
                   <label className="text-[10px] font-mono text-gray-500 uppercase tracking-widest">Initialized At</label>
                   <div className="text-gray-300 font-mono text-sm">{joinDate}</div>
                </div>
            </div>
        </div>

        {/* Stats Strip */}
        <div className="grid grid-cols-3 gap-1 mb-8">
           {[
             { label: "ENTRIES", value: animeCount, color: "text-[#00ff9f]" },
             { label: "HOURS", value: formatMinutes(stats.lifetimeMinutes).split(' ')[0], color: "text-[#ff0055]" },
             { label: "EPISODES", value: Math.floor(stats.lifetimeMinutes / 24), color: "text-blue-400" }
           ].map((stat, i) => (
             <div key={i} className="bg-[#00ff9f]/5 border border-[#00ff9f]/20 p-2 text-center">
                <div className={`text-xl font-black font-mono ${stat.color}`}>{stat.value}</div>
                <div className="text-[9px] text-gray-500 font-mono tracking-widest uppercase">{stat.label}</div>
             </div>
           ))}
        </div>

        {/* Edit Form */}
        <div className="border-t border-gray-800 pt-6 space-y-6">
            {message && (
              <div className={`p-3 border font-mono text-xs flex items-center gap-2 animate-fade-in ${
                  message.type === 'success' 
                  ? 'bg-green-900/20 border-green-500 text-green-400' 
                  : 'bg-red-900/20 border-red-500 text-red-400'
              }`}>
                  {message.type === 'success' ? <CheckCircle className="w-4 h-4"/> : <AlertCircle className="w-4 h-4"/>}
                  {message.text}
              </div>
            )}

            <form onSubmit={handleUpdateProfile} className="space-y-4">
               <div className="flex gap-4 items-end">
                  <div className="flex-1">
                     <CyberInput 
                       label="Update Alias"
                       value={displayName}
                       onChange={(e) => setDisplayName(e.target.value)}
                       placeholder="Input new designation..."
                     />
                  </div>
                  <CyberButton type="submit" primary disabled={loading || uploading}>
                     <Save className="w-4 h-4" />
                  </CyberButton>
               </div>
            </form>

            {user.providerData.some(p => p?.providerId === 'password') && (
               <div className="pt-2">
                 <CyberButton onClick={handlePasswordReset} className="w-full text-xs" disabled={loading || uploading}>
                    <Key className="w-4 h-4" />
                    Reset Access Key
                 </CyberButton>
               </div>
            )}
        </div>
      </CyberCard>
    </div>
  );
};

export interface Anime {
  mal_id: number;
  title: string;
  images: {
    jpg: {
      large_image_url: string;
      image_url: string;
    };
  };
  episodes: number | null;
  genres: { name: string }[];
  score?: number;
  synopsis?: string;
}

export interface ThemeSettings {
  mode: 'dark' | 'light';
  accentColor: string;
  accentName: string;
}

export interface WatchListEntry {
  id: string; // Firestore ID
  animeId: number;
  title: string;
  imageUrl: string;
  totalEpisodes: number | null;
  watchedEpisodes: number;
  genres: string[];
  updatedAt: string; // ISO String
  pending?: boolean; // True if data has not yet synced to the cloud
}

export interface WatchHistoryItem {
  id?: string;
  animeId: number;
  animeTitle?: string;
  episodesDelta: number;
  timestamp: string; // ISO String
}

export interface UserStats {
  todayMinutes: number;
  monthMinutes: number;
  yearMinutes: number;
  lifetimeMinutes: number;
}

import React, { useState, useEffect, useMemo } from 'react';
import firebase from 'firebase/compat/app';
import { auth, db, googleProvider } from './firebase';
import { Anime, WatchListEntry, WatchHistoryItem, ThemeSettings } from './types';
import { calculateStats } from './services/statsService';
import { AnimeSearch } from './components/AnimeSearch';
import { AnimeCard } from './components/AnimeCard';
import { StatsBoard } from './components/StatsBoard';
import { UserProfile } from './components/UserProfile';
import { HistoryModal } from './components/HistoryModal';
import { HomePage } from './components/HomePage';
import { CyberBackground, CyberButton, CyberInput, CyberCard, GlitchText } from './components/CyberUI';
import { Logo } from './components/Logo';
import { AmbientSound } from './components/AmbientSound';
import { Loader2, LogOut, History, ArrowLeft, Ghost, Wifi, AlertTriangle, X, CloudOff, Cloud, RefreshCw, UserCheck, Zap, Palette } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<firebase.User | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [watchlist, setWatchlist] = useState<WatchListEntry[]>([]);
  const [history, setHistory] = useState<WatchHistoryItem[]>([]);
  const [sortType, setSortType] = useState<'updated' | 'title'>('updated');
  const [showProfile, setShowProfile] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [isOffline, setIsOffline] = useState(!navigator.onLine);
  const [hasPendingWrites, setHasPendingWrites] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSyncTime, setLastSyncTime] = useState<Date | null>(null);
  const [themeSettings, setThemeSettings] = useState<ThemeSettings | null>(null);

  // Auth Form State
  const [showAuth, setShowAuth] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isSignUp, setIsSignUp] = useState(false);
  const [error, setError] = useState('');
  const [formLoading, setFormLoading] = useState(false);

  // Apply theme to document
  useEffect(() => {
    if (themeSettings) {
      const root = document.documentElement;
      root.style.setProperty('--accent-color', themeSettings.accentColor);

      // Calculate a dim version for glow effects
      const r = parseInt(themeSettings.accentColor.slice(1, 3), 16);
      const g = parseInt(themeSettings.accentColor.slice(3, 5), 16);
      const b = parseInt(themeSettings.accentColor.slice(5, 7), 16);
      root.style.setProperty('--accent-dim', `rgba(${r}, ${g}, ${b}, 0.3)`);

      if (themeSettings.mode === 'light') {
        root.classList.add('light');
        root.classList.remove('dark');
      } else {
        root.classList.add('dark');
        root.classList.remove('light');
      }
    } else {
      // Default
      document.documentElement.classList.add('dark');
    }
  }, [themeSettings]);

  // Network Listener
  useEffect(() => {
    const handleOnline = () => setIsOffline(false);
    const handleOffline = () => setIsOffline(true);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Auth Listener
  useEffect(() => {
    const unsubscribe = auth.onAuthStateChanged((currentUser) => {
      setUser(currentUser);
      setAuthLoading(false);
      if (currentUser) {
        setShowAuth(false);
      }
    });
    return () => unsubscribe();
  }, []);

  // Theme Listener
  useEffect(() => {
    if (!user) return;
    const unsub = db.collection('users').doc(user.uid).onSnapshot((doc) => {
      if (doc.exists) {
        const data = doc.data();
        if (data?.theme) {
          setThemeSettings(data.theme);
        }
      }
    });
    return () => unsub();
  }, [user]);

  // Helper to convert Firestore timestamp to ISO string
  const formatFirestoreDate = (val: any): string => {
    if (!val) return new Date().toISOString();
    if (typeof val.toDate === 'function') return val.toDate().toISOString();
    return val;
  };

  // Forced Sync Mechanism to ensure cross-device consistency
  const syncData = async () => {
    if (!user) return;
    setIsSyncing(true);
    setError('');

    try {
      // Pull fresh data directly from server to bypass local cache stubs
      const watchlistRef = db.collection('users').doc(user.uid).collection('watchlist');
      const historyRef = db.collection('users').doc(user.uid).collection('history');

      const [wSnap, hSnap] = await Promise.all([
        watchlistRef.get({ source: 'server' }),
        historyRef.get({ source: 'server' })
      ]);

      const wList = wSnap.docs.map(doc => ({ 
        id: doc.id, 
        ...doc.data(),
        updatedAt: formatFirestoreDate(doc.get('updatedAt'))
      })) as WatchListEntry[];

      const hList = hSnap.docs.map(doc => ({ 
        id: doc.id, 
        ...doc.data(),
        timestamp: formatFirestoreDate(doc.get('timestamp'))
      })) as WatchHistoryItem[];

      setWatchlist(wList);
      setHistory(hList);
      setLastSyncTime(new Date());
    } catch (err: any) {
      console.warn("Server sync attempt failed:", err);
      setError("SYNC_LINK_TIMEOUT: Retrying with local cache.");
    } finally {
      setIsSyncing(false);
    }
  };

  useEffect(() => {
    if (!user) {
      setWatchlist([]);
      setHistory([]);
      return;
    }

    const userRef = db.collection('users').doc(user.uid);

    // Optimized Real-time listener
    const unsubWatchlist = userRef.collection('watchlist').onSnapshot({ includeMetadataChanges: true }, (snapshot) => {
      const list = snapshot.docs.map(doc => {
        const data = doc.data();
        return {
          id: doc.id,
          ...data,
          updatedAt: formatFirestoreDate(data.updatedAt),
          pending: doc.metadata.hasPendingWrites
        };
      }) as WatchListEntry[];

      setWatchlist(list);
      setHasPendingWrites(snapshot.metadata.hasPendingWrites);
      if (!snapshot.metadata.hasPendingWrites) {
        setLastSyncTime(new Date());
      }
    }, (err) => {
        console.error("Watchlist Listener Error:", err);
        setError(`DATABASE_STREAM_ERR: ${err.message}`);
    });

    const unsubHistory = userRef.collection('history').onSnapshot((snapshot) => {
      const hist = snapshot.docs.map(doc => {
        const data = doc.data();
        return {
          id: doc.id,
          ...data,
          timestamp: formatFirestoreDate(data.timestamp)
        };
      }) as WatchHistoryItem[];
      setHistory(hist);
    });

    // Detect when everything is in sync with server
    const unsubSync = db.onSnapshotsInSync(() => {
      setHasPendingWrites(false);
    });

    return () => {
      unsubWatchlist();
      unsubHistory();
      unsubSync();
    };
  }, [user]);

  const sortedWatchlist = useMemo(() => {
    const data = [...watchlist];
    if (sortType === 'updated') {
      return data.sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime());
    } else {
      return data.sort((a, b) => a.title.localeCompare(b.title));
    }
  }, [watchlist, sortType]);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setFormLoading(true);
    try {
      if (isSignUp) {
        await auth.createUserWithEmailAndPassword(email, password);
      } else {
        await auth.signInWithEmailAndPassword(email, password);
      }
    } catch (err: any) {
      setError(err.message.replace('Firebase: ', ''));
    } finally {
      setFormLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
    setError('');
    setFormLoading(true);
    try {
      await auth.signInWithPopup(googleProvider);
    } catch (err: any) {
      setError(err.message.replace('Firebase: ', ''));
      setFormLoading(false);
    }
  };

  const handleLogout = () => {
      setError('');
      auth.signOut();
  };

  const addAnimeToLibrary = async (anime: Anime, initialWatched: number) => {
    if (!user) return;
    try {
        const batch = db.batch();
        const watchlistRef = db.collection('users').doc(user.uid).collection('watchlist').doc();

        const newEntry = {
          animeId: anime.mal_id,
          title: anime.title,
          imageUrl: anime.images.jpg.large_image_url,
          totalEpisodes: anime.episodes,
          watchedEpisodes: initialWatched,
          genres: anime.genres.map(g => g.name),
          updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        };

        batch.set(watchlistRef, newEntry);

        if (initialWatched > 0) {
            const historyRef = db.collection('users').doc(user.uid).collection('history').doc();
            batch.set(historyRef, {
                animeId: anime.mal_id,
                animeTitle: anime.title,
                episodesDelta: initialWatched,
                timestamp: firebase.firestore.FieldValue.serverTimestamp()
            });
        }

        // Commit batch for atomic consistency and performance
        await batch.commit();
    } catch (err: any) {
        setError(`WRITE_ERROR: ${err.message}`);
    }
  };

  const updateEpisodes = async (entry: WatchListEntry, newAmount: number) => {
    if (!user) return;
    const delta = newAmount - entry.watchedEpisodes;
    if (delta === 0) return;

    try {
        const batch = db.batch();
        const entryRef = db.collection('users').doc(user.uid).collection('watchlist').doc(entry.id);
        const historyRef = db.collection('users').doc(user.uid).collection('history').doc();

        batch.update(entryRef, {
          watchedEpisodes: newAmount,
          updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });

        batch.set(historyRef, {
          animeId: entry.animeId,
          animeTitle: entry.title,
          episodesDelta: delta,
          timestamp: firebase.firestore.FieldValue.serverTimestamp()
        });

        await batch.commit();
    } catch (err: any) {
        setError(`UPDATE_ERROR: ${err.message}`);
    }
  };

  if (authLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-black text-accent">
        <div className="flex flex-col items-center gap-4">
            <Loader2 className="w-12 h-12 animate-spin text-accent" />
            <div className="font-mono text-sm animate-pulse uppercase tracking-[0.2em] text-accent">Matrix_Link_Establishing...</div>
        </div>
      </div>
    );
  }

  if (!user) {
    if (!showAuth) {
        return (
          <>
            <HomePage onStart={() => setShowAuth(true)} isDark={true} toggleTheme={() => {}} />
            <AmbientSound />
          </>
        );
    }

    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-4 relative overflow-hidden bg-black text-white">
        <CyberBackground />
        <AmbientSound />
        <button onClick={() => setShowAuth(false)} className="absolute top-6 left-6 z-50 text-gray-500 hover:text-accent flex items-center gap-2 font-mono text-xs transition-colors">
          <ArrowLeft className="w-4 h-4" /> <span>ABORT_SEQUENCE</span>
        </button>
        <CyberCard className="w-full max-w-md animate-slide-up">
          <div className="p-8">
            <div className="text-center mb-10">
              <div className="flex justify-center mb-6 relative">
                 <div className="absolute inset-0 bg-accent/20 blur-2xl rounded-full" />
                 <Logo className="w-24 h-24 relative z-10 drop-shadow-[0_0_10px_var(--accent-dim)] animate-pulse" />
              </div>
              <h1 className="text-3xl font-black text-white tracking-tighter mb-1"><GlitchText>ACCESS_CONTROL</GlitchText></h1>
              <p className="text-accent font-mono text-[10px] tracking-[0.2em] uppercase">Verify Identity to Proceed</p>
            </div>
            <form onSubmit={handleAuth} className="space-y-6">
              <CyberInput label="User ID / Email" type="email" required value={email} onChange={(e) => setEmail(e.target.value)} placeholder="runner@net.city" />
              <CyberInput label="Access Key / Password" type="password" required value={password} onChange={(e) => setPassword(e.target.value)} placeholder="••••••••" />
              {error && <div className="p-3 border border-cyber-pink bg-cyber-pink/10 text-cyber-pink text-xs font-mono flex items-center gap-2"><Wifi className="w-4 h-4"/> ERROR: {error}</div>}
              <CyberButton type="submit" primary className="w-full" disabled={formLoading}>
                {formLoading ? <div className="flex items-center justify-center gap-2"><Loader2 className="w-5 h-5 animate-spin" /><span>PROCESSING...</span></div> : (isSignUp ? 'Initialize_Account' : 'Jack_In')}
              </CyberButton>
            </form>
            <div className="mt-8 relative"><div className="absolute inset-0 flex items-center"><div className="w-full border-t border-gray-800"></div></div><div className="relative flex justify-center text-xs"><span className="bg-black px-2 text-gray-600 font-mono">ALTERNATE_UPLINK</span></div></div>
            <button type="button" onClick={handleGoogleLogin} disabled={formLoading} className={`mt-6 w-full py-3 bg-white hover:bg-gray-100 text-black font-sans font-bold text-sm transition-all flex items-center justify-center gap-3 uppercase tracking-wider group shadow-[0_0_15px_rgba(255,255,255,0.1)] hover:shadow-[0_0_20px_rgba(255,255,255,0.3)] ${formLoading ? 'opacity-50 cursor-not-allowed' : ''}`} style={{ clipPath: 'polygon(10px 0, 100% 0, 100% calc(100% - 10px), calc(100% - 10px) 100%, 0 100%, 0 10px)' }}>
              <svg className="w-5 h-5" viewBox="0 0 24 24">
                <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4" />
                <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853" />
                <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05" />
                <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335" />
              </svg>
              <span>Sign In with Google</span>
            </button>
            <div className="mt-8 text-center">
              <button onClick={() => setIsSignUp(!isSignUp)} className="text-xs text-accent hover:text-white font-mono hover:underline decoration-accent underline-offset-4">
                {isSignUp ? "HAS_ACCOUNT? EXECUTE LOGIN" : "NO_DATA? CREATE NEW RECORD"}
              </button>
            </div>
          </div>
        </CyberCard>
      </div>
    );
  }

  const stats = calculateStats(history, watchlist);

  return (
    <div className="min-h-screen relative pb-20 font-sans selection:bg-cyber-pink selection:text-white bg-[var(--bg-color)] text-[var(--text-color)] transition-colors duration-500">
      <CyberBackground />
      <AmbientSound />

      <header className="sticky top-0 z-40 bg-[var(--bg-color)]/80 backdrop-blur-md border-b border-white/10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-3 group">
            <Logo className="w-10 h-10 hover:scale-110 transition-transform duration-300" />
            <span className="font-mono font-bold text-xl tracking-tighter text-white group-hover:text-accent transition-colors">ANI<span className="text-accent">TRACK</span></span>

            {/* Sync Pulse Component */}
            <button 
              onClick={syncData}
              className="ml-4 flex items-center gap-2 border-l border-gray-800 pl-4 h-8 group/sync"
            >
               {hasPendingWrites || isSyncing ? (
                 <div className="flex items-center gap-2 text-amber-500 animate-pulse" title="Syncing to Cloud...">
                    <RefreshCw className="w-3.5 h-3.5 animate-spin" />
                    <span className="text-[10px] font-mono font-bold hidden md:inline">UPLINKING...</span>
                 </div>
               ) : (
                 <div className="flex items-center gap-2 text-accent" title="Synchronized with Matrix">
                    <Cloud className="w-4 h-4 group-hover/sync:scale-110 transition-transform" />
                    <span className="text-[10px] font-mono font-bold hidden md:inline">SYNCHRONIZED</span>
                 </div>
               )}
            </button>
          </div>

          <div className="flex items-center gap-6">
            <div className="hidden lg:flex flex-col items-end cursor-default font-mono border-r border-gray-800 pr-6 mr-2">
                <span className="text-xs font-bold text-accent leading-none mb-1 flex items-center gap-2">
                   <UserCheck className="w-3 h-3 text-accent" /> {user.displayName || 'ANON_RUNNER'}
                </span>
                <span className="text-[9px] text-gray-500 uppercase tracking-widest">{lastSyncTime ? `LAST_SYNC: ${lastSyncTime.toLocaleTimeString()}` : 'WAITING_FOR_DATA'}</span>
            </div>

            <div className="flex items-center gap-4">
                <button onClick={() => setShowProfile(true)} className="w-10 h-10 border border-gray-700 hover:border-accent transition-all flex items-center justify-center overflow-hidden bg-black relative">
                     {user.photoURL ? <img src={user.photoURL} alt="User" className="w-full h-full object-cover opacity-80" /> : <Ghost className="w-5 h-5 text-gray-500" />}
                     <div className="absolute top-0 right-0 w-2 h-2 bg-accent border border-black rounded-full" />
                </button>
                <button onClick={handleLogout} className="p-2 text-gray-600 hover:text-red-500 transition-colors" title="Sever Connection">
                  <LogOut className="w-5 h-5" />
                </button>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 pt-10 relative z-10">
        {(error || isOffline) && (
          <div className={`mb-8 p-4 border flex items-center justify-between gap-4 animate-fade-in ${isOffline ? 'bg-amber-900/20 border-amber-500 text-amber-500' : 'bg-cyber-pink/10 border-cyber-pink text-cyber-pink'}`}>
            <div className="flex items-center gap-3">
               {isOffline ? <CloudOff className="w-6 h-6" /> : <AlertTriangle className="w-6 h-6" />}
               <div>
                  <h3 className="font-bold font-mono tracking-wider">{isOffline ? 'OFFLINE_MODE' : 'SYNC_PROTOCOL_ERROR'}</h3>
                  <p className="text-xs font-mono opacity-80">{isOffline ? 'LOCAL_CACHE_ONLY. RECONNECT TO UPLOAD.' : error}</p>
               </div>
            </div>
            <div className="flex items-center gap-2">
               {!isOffline && <CyberButton onClick={syncData} className="text-[10px] px-3 py-1">Retry_Link</CyberButton>}
               <button onClick={() => setError('')} className="p-2 hover:bg-white/10 rounded"><X className="w-5 h-5" /></button>
            </div>
          </div>
        )}

        <section className="mb-16 animate-fade-in">
          <div className="flex items-end justify-between mb-8 border-b border-white/10 pb-4">
             <div><h2 className="text-2xl font-black text-[var(--text-color)] uppercase tracking-tight mb-1">Data Overview</h2><div className="text-[10px] font-mono text-gray-500">NEURAL_DASHBOARD</div></div>
             <button onClick={() => setShowHistory(true)} className="flex items-center gap-2 px-4 py-2 bg-white/5 border border-white/10 hover:border-accent text-gray-400 text-xs font-mono transition-all uppercase tracking-wider">
               <History className="w-3 h-3" /> View Logs
             </button>
          </div>
          <StatsBoard stats={stats} />
        </section>

        <section className="mb-20 flex flex-col items-center">
          <div className="w-full max-w-2xl text-center mb-8">
             <h2 className="text-xl font-bold text-[var(--text-color)] uppercase tracking-widest mb-2"><GlitchText>Database Entry</GlitchText></h2>
             <div className="h-0.5 w-24 bg-accent mx-auto" />
          </div>
          <AnimeSearch onAddAnime={addAnimeToLibrary} watchlist={watchlist} />
        </section>

        <section>
          <div className="flex flex-col sm:flex-row items-end justify-between mb-8 gap-4 border-b border-white/10 pb-4">
            <div className="flex items-center gap-4">
                <h2 className="text-3xl font-black text-[var(--text-color)] flex items-center gap-3 uppercase">MEMORY BANK <span className="text-lg font-mono font-normal text-accent border border-accent px-2 py-0.5">{watchlist.length}</span></h2>
                <button onClick={syncData} disabled={isSyncing} className={`p-2 border border-gray-800 text-gray-600 hover:text-accent hover:border-accent transition-all rounded-full ${isSyncing ? 'animate-spin' : ''}`} title="Force Refresh from Cloud">
                   <RefreshCw className="w-4 h-4" />
                </button>
            </div>
            <div className="flex items-center gap-3">
              <span className="text-[10px] font-mono text-gray-500 uppercase">Sort_Type:</span>
              <div className="flex gap-1">
                <button onClick={() => setSortType('updated')} className={`px-3 py-1 text-[10px] font-mono border ${sortType === 'updated' ? 'bg-accent/20 border-accent text-accent' : 'border-gray-800 text-gray-500 hover:border-gray-600'}`}>Recent</button>
                <button onClick={() => setSortType('title')} className={`px-3 py-1 text-[10px] font-mono border ${sortType === 'title' ? 'bg-accent/20 border-accent text-accent' : 'border-gray-800 text-gray-500 hover:border-gray-600'}`}>Alpha</button>
              </div>
            </div>
          </div>

          {watchlist.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-24 border border-dashed border-gray-800 bg-white/5">
              <Ghost className="w-16 h-16 text-gray-800 mb-4" />
              <p className="font-mono text-gray-500 text-lg uppercase">Memory Void</p>
              <p className="font-mono text-gray-700 text-[10px] mt-2 tracking-widest uppercase">Initializing neural link... search to populate</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 sm:gap-6 lg:gap-8">
              {sortedWatchlist.map((entry) => (
                <AnimeCard 
                  key={entry.id} 
                  entry={entry} 
                  onUpdateEpisodes={updateEpisodes} 
                  onRemove={(id) => {
                    if (window.confirm("WARNING: Confirm deletion of database entry.")) {
                      db.collection('users').doc(user.uid).collection('watchlist').doc(id).delete();
                    }
                  }} 
                />
              ))}
            </div>
          )}
        </section>
      </main>

      {showProfile && user && <UserProfile user={user} stats={stats} animeCount={watchlist.length} themeSettings={themeSettings} onClose={() => setShowProfile(false)} />}
      {showHistory && <HistoryModal history={history} watchlist={watchlist} onClose={() => setShowHistory(false)} onUpdate={async (id, data) => {
        await db.collection('users').doc(user.uid).collection('history').doc(id).update(data);
      }} onDelete={async (id) => {
        await db.collection('users').doc(user.uid).collection('history').doc(id).delete();
      }} />}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import firebase from 'firebase/compat/app';
import { auth, storage, db } from '../firebase';
import { UserStats, ThemeSettings } from '../types';
import { formatMinutes } from '../services/statsService';
import { X, User as UserIcon, Save, Key, AlertCircle, CheckCircle, Database, Camera, Loader2, Zap, ShieldCheck, Palette, Moon, Sun } from 'lucide-react';
import { CyberButton, CyberInput, CyberCard, GlitchText } from './CyberUI';

interface UserProfileProps {
  user: firebase.User;
  stats: UserStats;
  animeCount: number;
  themeSettings: ThemeSettings | null;
  onClose: () => void;
}

const ACCENT_PRESETS = [
  { name: 'Emerald', color: '#00ff9f' },
  { name: 'Rose', color: '#ff0055' },
  { name: 'Cyan', color: '#00baee' },
  { name: 'Amethyst', color: '#bc13fe' },
  { name: 'Amber', color: '#ffb000' }
];

export const UserProfile: React.FC<UserProfileProps> = ({ user, stats, animeCount, themeSettings, onClose }) => {
  const [displayName, setDisplayName] = useState(user.displayName || '');
  const [loading, setLoading] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [currentMode, setCurrentMode] = useState<'dark' | 'light'>(themeSettings?.mode || 'dark');
  const [currentAccent, setCurrentAccent] = useState(themeSettings?.accentColor || '#00ff9f');

  useEffect(() => {
    if (themeSettings) {
      setCurrentMode(themeSettings.mode);
      setCurrentAccent(themeSettings.accentColor);
    }
  }, [themeSettings]);

  const handleUpdateProfile = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setMessage(null);
    try {
      await user.updateProfile({ displayName });
      setMessage({ type: 'success', text: 'IDENTITY_RECORD UPDATED' });
    } catch (error: any) {
      setMessage({ type: 'error', text: `SYNC_FAILED: ${error.message}` });
    } finally {
      setLoading(false);
    }
  };

  const handleSaveTheme = async (mode: 'dark' | 'light', colorObj: {name: string, color: string}) => {
    setLoading(true);
    try {
      await db.collection('users').doc(user.uid).set({
        theme: {
          mode,
          accentColor: colorObj.color,
          accentName: colorObj.name
        }
      }, { merge: true });
      setMessage({ type: 'success', text: 'THEME_SYNC_SUCCESSFUL' });
    } catch (err: any) {
      setMessage({ type: 'error', text: `THEME_SYNC_FAILED: ${err.message}` });
    } finally {
      setLoading(false);
    }
  };

  const handlePasswordReset = async () => {
    if (!user.email) return;
    setLoading(true);
    setMessage(null);
    try {
        await auth.sendPasswordResetEmail(user.email);
        setMessage({ type: 'success', text: 'RESET_PROTOCOL INITIATED. CHECK INBOX.' });
    } catch (error: any) {
        setMessage({ type: 'error', text: error.message });
    } finally {
        setLoading(false);
    }
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!file.type.startsWith('image/')) {
        setMessage({ type: 'error', text: 'INVALID FORMAT. IMAGE REQUIRED.' });
        return;
    }

    if (file.size > 5 * 1024 * 1024) {
      setMessage({ type: 'error', text: 'PAYLOAD TOO LARGE. MAX 5MB.' });
      return;
    }

    setUploading(true);
    setMessage(null);

    const reader = new FileReader();
    reader.onload = async (event) => {
      const dataUrl = event.target?.result as string;
      if (!dataUrl) {
        setMessage({ type: 'error', text: 'READ_ERROR: FAILED TO PROCESS IMAGE.' });
        setUploading(false);
        return;
      }

      try {
          const fileExtension = file.name.split('.').pop() || 'jpg';
          const storagePath = `avatars/${user.uid}/${Date.now()}.${fileExtension}`;
          const storageRef = storage.ref().child(storagePath);
          const snapshot = await storageRef.putString(dataUrl, 'data_url');
          const photoURL = await snapshot.ref.getDownloadURL();
          await user.updateProfile({ photoURL });
          await user.reload(); 
          setMessage({ type: 'success', text: 'AVATAR SYNCED TO SECURE_STORAGE.' });
      } catch (error: any) {
          setMessage({ type: 'error', text: `UPLINK_FAILED: ${error.message}` });
      } finally {
          setUploading(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const joinDate = user.metadata.creationTime 
    ? new Date(user.metadata.creationTime).toLocaleDateString('en-US', { year: 'numeric', month: '2-digit', day: '2-digit' })
    : 'UNKNOWN';

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md animate-fade-in overflow-y-auto">
      <CyberCard className="w-full max-w-lg my-auto">

        {/* Header Bar */}
        <div className="flex items-center justify-between mb-8 border-b border-accent/20 pb-4">
          <div className="flex items-center gap-3">
             <Database className="w-5 h-5 text-cyber-pink animate-pulse" />
             <GlitchText className="text-xl font-mono font-bold text-[var(--text-color)] tracking-widest">
                IDENTITY_MODULE
             </GlitchText>
          </div>
          <button onClick={onClose} className="text-gray-500 hover:text-cyber-pink transition-colors"><X className="w-6 h-6" /></button>
        </div>

        <div className="flex flex-col md:flex-row gap-8 mb-8">
            <div className="flex flex-col items-center justify-center">
                <div className="relative w-24 h-24 mb-4 group">
                    <div className={`absolute inset-0 border-2 ${uploading ? 'border-cyber-pink animate-spin' : 'border-accent border-dashed animate-spin-slow'}`}></div>
                    <div className="absolute inset-2 bg-gray-900 rounded-full overflow-hidden border border-gray-700 flex items-center justify-center">
                        {user.photoURL ? (
                            <img src={user.photoURL} alt="Profile" className="w-full h-full object-cover opacity-80 group-hover:opacity-50 transition-opacity" />
                        ) : (
                            <UserIcon className="w-10 h-10 text-gray-500 group-hover:text-accent transition-colors" />
                        )}
                    </div>
                    <button 
                        onClick={() => fileInputRef.current?.click()}
                        disabled={uploading}
                        className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity bg-black/50 rounded-full cursor-pointer z-10"
                    >
                        {uploading ? <Loader2 className="w-6 h-6 text-accent animate-spin" /> : <Camera className="w-6 h-6 text-accent" />}
                    </button>
                    <input type="file" ref={fileInputRef} onChange={handleImageUpload} className="hidden" accept="image/*" />
                </div>
                <div className="text-center">
                    <div className="text-[10px] font-mono text-accent flex items-center gap-1 justify-center">
                      <ShieldCheck className="w-2.5 h-2.5" /> SECURE_VAULT_ACTIVE
                    </div>
                    <div className="text-[10px] font-mono text-gray-500 mt-1 uppercase tracking-tighter">UID: {user.uid.substring(0,8)}</div>
                </div>
            </div>

            <div className="flex-1 space-y-4">
                <div>
                   <label className="text-[10px] font-mono text-gray-500 uppercase tracking-widest">Designation</label>
                   <div className="text-[var(--text-color)] font-bold text-lg">{user.displayName || 'ANONYMOUS_RUNNER'}</div>
                </div>
                <div>
                   <label className="text-[10px] font-mono text-gray-500 uppercase tracking-widest">Uplink Address</label>
                   <div className="text-gray-400 font-mono text-sm">{user.email}</div>
                </div>
                <div>
                   <label className="text-[10px] font-mono text-gray-500 uppercase tracking-widest">Initialized At</label>
                   <div className="text-gray-400 font-mono text-sm">{joinDate}</div>
                </div>
            </div>
        </div>

        {/* Customization Section */}
        <div className="mb-8 p-4 bg-accent/5 border border-accent/20">
          <div className="flex items-center gap-2 mb-4">
            <Palette className="w-4 h-4 text-accent" />
            <h4 className="text-xs font-mono font-bold text-accent uppercase tracking-widest">Neural Theme Config</h4>
          </div>

          <div className="space-y-6">
            {/* Mode Toggle */}
            <div className="flex items-center justify-between">
              <span className="text-[10px] font-mono text-gray-500 uppercase">Visual_Mode</span>
              <div className="flex gap-2">
                 <button 
                  onClick={() => handleSaveTheme('dark', ACCENT_PRESETS.find(p => p.color === currentAccent) || ACCENT_PRESETS[0])}
                  className={`p-2 border transition-all ${currentMode === 'dark' ? 'border-accent text-accent bg-accent/10' : 'border-gray-800 text-gray-600'}`}
                 >
                   <Moon className="w-4 h-4" />
                 </button>
                 <button 
                  onClick={() => handleSaveTheme('light', ACCENT_PRESETS.find(p => p.color === currentAccent) || ACCENT_PRESETS[0])}
                  className={`p-2 border transition-all ${currentMode === 'light' ? 'border-accent text-accent bg-accent/10' : 'border-gray-800 text-gray-600'}`}
                 >
                   <Sun className="w-4 h-4" />
                 </button>
              </div>
            </div>

            {/* Accent Colors */}
            <div>
              <span className="text-[10px] font-mono text-gray-500 uppercase block mb-3">Sync_Accent_Uplink</span>
              <div className="flex flex-wrap gap-2">
                {ACCENT_PRESETS.map((preset) => (
                  <button
                    key={preset.name}
                    onClick={() => handleSaveTheme(currentMode, preset)}
                    className={`flex items-center gap-2 px-3 py-1.5 border font-mono text-[9px] uppercase transition-all ${
                      currentAccent === preset.color 
                        ? 'border-accent bg-accent/20 text-accent' 
                        : 'border-gray-800 text-gray-600 hover:border-gray-500'
                    }`}
                  >
                    <div className="w-2 h-2 rounded-full" style={{ backgroundColor: preset.color }} />
                    {preset.name}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* Stats Strip */}
        <div className="grid grid-cols-3 gap-1 mb-8">
           {[
             { label: "ENTRIES", value: animeCount, color: "text-accent" },
             { label: "HOURS", value: formatMinutes(stats.lifetimeMinutes).split(' ')[0], color: "text-cyber-pink" },
             { label: "EPISODES", value: Math.floor(stats.lifetimeMinutes / 24), color: "text-blue-400" }
           ].map((stat, i) => (
             <div key={i} className="bg-accent/5 border border-accent/20 p-2 text-center">
                <div className={`text-xl font-black font-mono ${stat.color}`}>{stat.value}</div>
                <div className="text-[9px] text-gray-500 font-mono tracking-widest uppercase">{stat.label}</div>
             </div>
           ))}
        </div>

        {/* Edit Form */}
        <div className="border-t border-gray-800 pt-6 space-y-6">
            {message && (
              <div className={`p-3 border font-mono text-xs flex items-center gap-2 animate-fade-in ${
                  message.type === 'success' 
                  ? 'bg-green-900/20 border-green-500 text-green-400' 
                  : 'bg-red-900/20 border-red-500 text-red-400'
              }`}>
                  {message.type === 'success' ? <CheckCircle className="w-4 h-4"/> : <AlertCircle className="w-4 h-4"/>}
                  {message.text}
              </div>
            )}

            <form onSubmit={handleUpdateProfile} className="space-y-4">
               <div className="flex gap-4 items-end">
                  <div className="flex-1">
                     <CyberInput 
                       label="Update Alias"
                       value={displayName}
                       onChange={(e) => setDisplayName(e.target.value)}
                       placeholder="Input new designation..."
                     />
                  </div>
                  <CyberButton type="submit" primary disabled={loading || uploading}>
                     <Save className="w-4 h-4" />
                  </CyberButton>
               </div>
            </form>

            {user.providerData.some(p => p?.providerId === 'password') && (
               <div className="pt-2">
                 <CyberButton onClick={handlePasswordReset} className="w-full text-xs" disabled={loading || uploading}>
                    <Key className="w-4 h-4" />
                    Reset Access Key
                 </CyberButton>
               </div>
            )}
        </div>
      </CyberCard>
    </div>
  );
};

