import React, { useState, useEffect } from 'react';
import { Plus, Minus, Trash2, Activity, Cloud, RefreshCw } from 'lucide-react';
import { WatchListEntry } from '../types';
import { GENRE_COLORS } from '../constants';

interface AnimeCardProps {
  entry: WatchListEntry;
  onUpdateEpisodes: (entry: WatchListEntry, newAmount: number) => void;
  onRemove: (id: string) => void;
}

export const AnimeCard: React.FC<AnimeCardProps> = ({ entry, onUpdateEpisodes, onRemove }) => {
  const [loading, setLoading] = useState(false);
  const [isUpdating, setIsUpdating] = useState(false);

  // Trigger pulse effect when watched episodes change locally or via sync
  useEffect(() => {
    setIsUpdating(true);
    const timer = setTimeout(() => setIsUpdating(false), 800);
    return () => clearTimeout(timer);
  }, [entry.watchedEpisodes, entry.pending]);

  const handleUpdate = async (delta: number) => {
    const newAmount = entry.watchedEpisodes + delta;
    if (newAmount < 0) return;
    if (entry.totalEpisodes && newAmount > entry.totalEpisodes) return;

    // Optimistically set loading but keep interaction possible
    setLoading(true);
    await onUpdateEpisodes(entry, newAmount);
    setLoading(false);
  };

  const progress = entry.totalEpisodes 
    ? (entry.watchedEpisodes / entry.totalEpisodes) * 100 
    : 0;

  return (
    <div 
        className={`group relative bg-[var(--card-bg)] border transition-all duration-500 flex flex-col h-full animate-slide-up overflow-hidden ${
          entry.pending ? 'border-amber-500/50 shadow-[0_0_15px_rgba(245,158,11,0.1)]' : 'border-white/10 hover:border-accent'
        }`}
        style={{ clipPath: 'polygon(15px 0, 100% 0, 100% calc(100% - 15px), calc(100% - 15px) 100%, 0 100%, 0 15px)' }}
    >
      {/* Image Section */}
      <div className="relative aspect-[16/9] overflow-hidden border-b border-white/10">
        <img 
          src={entry.imageUrl} 
          alt={entry.title} 
          className={`w-full h-full object-cover transition-all duration-500 group-hover:scale-105 ${entry.pending ? 'grayscale opacity-60' : 'grayscale group-hover:grayscale-0'}`}
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black via-black/50 to-transparent" />

        {/* Title Overlay */}
        <div className="absolute bottom-0 left-0 p-4 w-full">
            <h3 className={`font-mono font-bold text-lg leading-tight line-clamp-1 drop-shadow-[0_2px_4px_rgba(0,0,0,0.8)] transition-colors ${entry.pending ? 'text-amber-500' : 'text-white'}`}>
                {entry.title}
            </h3>
            <div className={`h-[2px] mt-2 transition-all duration-500 ${entry.pending ? 'w-1/2 bg-amber-500 animate-pulse' : 'w-10 bg-accent group-hover:w-full'}`} />
        </div>

        {/* Delete Button */}
        <button 
          onClick={() => onRemove(entry.id)}
          className="absolute top-0 right-0 p-2 bg-black/60 text-gray-500 hover:text-red-500 hover:bg-black transition-colors backdrop-blur-sm z-10"
        >
          <Trash2 className="w-4 h-4" />
        </button>

        {/* Sync Indicator for Pending Writes */}
        {entry.pending && (
          <div className="absolute top-0 left-0 p-2 bg-amber-500/20 text-amber-500 backdrop-blur-sm flex items-center gap-1 font-mono text-[10px] border-r border-b border-amber-500/50 z-10">
             <RefreshCw className="w-3 h-3 animate-spin" />
             <span className="tracking-tighter">OFFLINE_STUB</span>
          </div>
        )}
      </div>

      {/* Content Section */}
      <div className="p-4 flex-1 flex flex-col justify-between backdrop-blur-sm relative">
        {/* Background update flash */}
        <div className={`absolute inset-0 bg-accent/5 pointer-events-none transition-opacity duration-500 ${isUpdating && !entry.pending ? 'opacity-100' : 'opacity-0'}`} />

        <div className="flex flex-wrap gap-1 mb-4 relative z-10">
          {entry.genres.slice(0, 3).map((genre) => {
             const colorClass = GENRE_COLORS[genre] || GENRE_COLORS['Default'];
             return (
              <span key={genre} className={`text-[9px] px-1.5 py-0.5 font-mono uppercase tracking-wider ${colorClass}`}>
                {genre}
              </span>
             );
          })}
        </div>

        <div className="relative z-10">
          {/* Progress Info */}
          <div className="flex justify-between items-end mb-2 font-mono text-xs">
            <span className={`transition-colors flex items-center gap-1 ${entry.pending ? 'text-amber-500/70' : 'text-gray-500 group-hover:text-accent'}`}>
               <Activity className="w-3 h-3" /> PROGRESS
            </span>
            <span className={entry.pending ? 'text-amber-500' : 'text-[var(--text-color)]'}>
              {entry.watchedEpisodes} <span className="text-gray-500">/ {entry.totalEpisodes || '?'}</span>
            </span>
          </div>

          {/* Progress Bar */}
          <div className={`w-full bg-gray-900/40 h-1.5 mb-4 border overflow-hidden rounded-sm transition-colors ${entry.pending ? 'border-amber-900/50' : 'border-gray-800'}`}>
            <div 
              className={`h-full relative transition-all duration-700 ease-[cubic-bezier(0.4,0,0.2,1)] ${
                entry.pending 
                  ? 'bg-amber-600 shadow-[0_0_10px_#d97706]' 
                  : isUpdating 
                    ? 'bg-accent shadow-[0_0_20px_var(--accent-color)] brightness-125' 
                    : 'bg-accent shadow-[0_0_5px_var(--accent-dim)]'
              }`}
              style={{ width: `${entry.totalEpisodes ? progress : 100}%` }}
            >
                {/* Scanline/Glitch effect on bar */}
                <div className={`absolute top-0 right-0 h-full w-1 bg-white opacity-50 ${entry.pending ? 'animate-pulse' : ''}`} />
            </div>
          </div>

          {/* Controls */}
          <div className="flex items-center justify-between gap-2">
            <button
              onClick={() => handleUpdate(-1)}
              disabled={loading || entry.watchedEpisodes <= 0}
              className="p-1.5 border border-gray-800 text-gray-500 hover:border-cyber-pink hover:text-cyber-pink hover:shadow-[0_0_10px_#ff0055] transition-all disabled:opacity-30 disabled:hover:border-gray-800"
            >
              <Minus className="w-4 h-4" />
            </button>

            <div className="flex flex-col items-center">
              <span className={`text-[10px] font-mono transition-colors ${entry.pending ? 'text-amber-500/50' : 'text-gray-500'}`}>
                {entry.watchedEpisodes * 24}m
              </span>
            </div>

            <button
              onClick={() => handleUpdate(1)}
              disabled={loading || (entry.totalEpisodes !== null && entry.watchedEpisodes >= entry.totalEpisodes)}
              className="p-1.5 border border-gray-800 text-gray-500 hover:border-accent hover:text-accent hover:shadow-[0_0_10px_var(--accent-dim)] transition-all disabled:opacity-30 disabled:hover:border-gray-800"
            >
              <Plus className="w-4 h-4" />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

