import React, { useState, useEffect, useMemo } from 'react';
import firebase from 'firebase/compat/app';
import { auth, db, googleProvider } from './firebase';
import { Anime, WatchListEntry, WatchHistoryItem, ThemeSettings } from './types';
import { calculateStats } from './services/statsService';
import { AnimeSearch } from './components/AnimeSearch';
import { AnimeCard } from './components/AnimeCard';
import { StatsBoard } from './components/StatsBoard';
import { UserProfile } from './components/UserProfile';
import { HistoryModal } from './components/HistoryModal';
import { HomePage } from './components/HomePage';
import { CyberBackground, CyberButton, CyberInput, CyberCard, GlitchText } from './components/CyberUI';
import { Logo } from './components/Logo';
import { AmbientSound } from './components/AmbientSound';
import { Loader2, LogOut, History, ArrowLeft, Ghost, Wifi, AlertTriangle, X, CloudOff, Cloud, RefreshCw, UserCheck, Zap, Palette } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<firebase.User | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [watchlist, setWatchlist] = useState<WatchListEntry[]>([]);
  const [history, setHistory] = useState<WatchHistoryItem[]>([]);
  const [sortType, setSortType] = useState<'updated' | 'title'>('updated');
  const [showProfile, setShowProfile] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [isOffline, setIsOffline] = useState(!navigator.onLine);
  const [hasPendingWrites, setHasPendingWrites] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSyncTime, setLastSyncTime] = useState<Date | null>(null);
  const [themeSettings, setThemeSettings] = useState<ThemeSettings | null>(null);

  // Auth Form State
  const [showAuth, setShowAuth] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isSignUp, setIsSignUp] = useState(false);
  const [error, setError] = useState('');
  const [formLoading, setFormLoading] = useState(false);

  // Apply theme to document with safety checks for hex colors
  useEffect(() => {
    const root = document.documentElement;
    if (themeSettings) {
      root.style.setProperty('--accent-color', themeSettings.accentColor);

      // Calculate a dim version for glow effects
      try {
        const hex = themeSettings.accentColor.replace('#', '');
        const r = parseInt(hex.substring(0, 2), 16);
        const g = parseInt(hex.substring(2, 4), 16);
        const b = parseInt(hex.substring(4, 6), 16);
        root.style.setProperty('--accent-dim', `rgba(${r}, ${g}, ${b}, 0.2)`);
      } catch (e) {
        root.style.setProperty('--accent-dim', `rgba(0, 255, 159, 0.2)`);
      }

      if (themeSettings.mode === 'light') {
        root.classList.add('light');
        root.classList.remove('dark');
      } else {
        root.classList.add('dark');
        root.classList.remove('light');
      }
    } else {
      // Default fallback
      root.classList.add('dark');
      root.classList.remove('light');
      root.style.setProperty('--accent-color', '#00ff9f');
      root.style.setProperty('--accent-dim', 'rgba(0, 255, 159, 0.2)');
    }
  }, [themeSettings]);

  // Network Listener
  useEffect(() => {
    const handleOnline = () => setIsOffline(false);
    const handleOffline = () => setIsOffline(true);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Auth Listener
  useEffect(() => {
    const unsubscribe = auth.onAuthStateChanged((currentUser) => {
      setUser(currentUser);
      setAuthLoading(false);
      if (currentUser) {
        setShowAuth(false);
      }
    });
    return () => unsubscribe();
  }, []);

  // Theme Listener
  useEffect(() => {
    if (!user) return;
    const unsub = db.collection('users').doc(user.uid).onSnapshot((doc) => {
      if (doc.exists) {
        const data = doc.data();
        if (data?.theme) {
          setThemeSettings(data.theme);
        }
      }
    });
    return () => unsub();
  }, [user]);

  // Helper to convert Firestore timestamp to ISO string
  const formatFirestoreDate = (val: any): string => {
    if (!val) return new Date().toISOString();
    if (typeof val.toDate === 'function') return val.toDate().toISOString();
    return val;
  };

  const syncData = async () => {
    if (!user) return;
    setIsSyncing(true);
    setError('');

    try {
      const watchlistRef = db.collection('users').doc(user.uid).collection('watchlist');
      const historyRef = db.collection('users').doc(user.uid).collection('history');

      const [wSnap, hSnap] = await Promise.all([
        watchlistRef.get({ source: 'server' }),
        historyRef.get({ source: 'server' })
      ]);

      const wList = wSnap.docs.map(doc => ({ 
        id: doc.id, 
        ...doc.data(),
        updatedAt: formatFirestoreDate(doc.get('updatedAt'))
      })) as WatchListEntry[];

      const hList = hSnap.docs.map(doc => ({ 
        id: doc.id, 
        ...doc.data(),
        timestamp: formatFirestoreDate(doc.get('timestamp'))
      })) as WatchHistoryItem[];

      setWatchlist(wList);
      setHistory(hList);
      setLastSyncTime(new Date());
    } catch (err: any) {
      console.warn("Server sync attempt failed:", err);
      setError("SYNC_LINK_TIMEOUT: Retrying with local cache.");
    } finally {
      setIsSyncing(false);
    }
  };

  useEffect(() => {
    if (!user) {
      setWatchlist([]);
      setHistory([]);
      return;
    }

    const userRef = db.collection('users').doc(user.uid);

    const unsubWatchlist = userRef.collection('watchlist').onSnapshot({ includeMetadataChanges: true }, (snapshot) => {
      const list = snapshot.docs.map(doc => {
        const data = doc.data();
        return {
          id: doc.id,
          ...data,
          updatedAt: formatFirestoreDate(data.updatedAt),
          pending: doc.metadata.hasPendingWrites
        };
      }) as WatchListEntry[];

      setWatchlist(list);
      setHasPendingWrites(snapshot.metadata.hasPendingWrites);
      if (!snapshot.metadata.hasPendingWrites) {
        setLastSyncTime(new Date());
      }
    }, (err) => {
        console.error("Watchlist Listener Error:", err);
        setError(`DATABASE_STREAM_ERR: ${err.message}`);
    });

    const unsubHistory = userRef.collection('history').onSnapshot((snapshot) => {
      const hist = snapshot.docs.map(doc => {
        const data = doc.data();
        return {
          id: doc.id,
          ...data,
          timestamp: formatFirestoreDate(data.timestamp)
        };
      }) as WatchHistoryItem[];
      setHistory(hist);
    });

    const unsubSync = db.onSnapshotsInSync(() => {
      setHasPendingWrites(false);
    });

    return () => {
      unsubWatchlist();
      unsubHistory();
      unsubSync();
    };
  }, [user]);

  const sortedWatchlist = useMemo(() => {
    const data = [...watchlist];
    if (sortType === 'updated') {
      return data.sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime());
    } else {
      return data.sort((a, b) => a.title.localeCompare(b.title));
    }
  }, [watchlist, sortType]);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setFormLoading(true);
    try {
      if (isSignUp) {
        await auth.createUserWithEmailAndPassword(email, password);
      } else {
        await auth.signInWithEmailAndPassword(email, password);
      }
    } catch (err: any) {
      setError(err.message.replace('Firebase: ', ''));
    } finally {
      setFormLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
    setError('');
    setFormLoading(true);
    try {
      await auth.signInWithPopup(googleProvider);
    } catch (err: any) {
      setError(err.message.replace('Firebase: ', ''));
      setFormLoading(false);
    }
  };

  const handleLogout = () => {
      setError('');
      auth.signOut();
  };

  const addAnimeToLibrary = async (anime: Anime, initialWatched: number) => {
    if (!user) return;
    try {
        const batch = db.batch();
        const watchlistRef = db.collection('users').doc(user.uid).collection('watchlist').doc();

        const newEntry = {
          animeId: anime.mal_id,
          title: anime.title,
          imageUrl: anime.images.jpg.large_image_url,
          totalEpisodes: anime.episodes,
          watchedEpisodes: initialWatched,
          genres: anime.genres.map(g => g.name),
          updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        };

        batch.set(watchlistRef, newEntry);

        if (initialWatched > 0) {
            const historyRef = db.collection('users').doc(user.uid).collection('history').doc();
            batch.set(historyRef, {
                animeId: anime.mal_id,
                animeTitle: anime.title,
                episodesDelta: initialWatched,
                timestamp: firebase.firestore.FieldValue.serverTimestamp()
            });
        }

        await batch.commit();
    } catch (err: any) {
        setError(`WRITE_ERROR: ${err.message}`);
    }
  };

  const updateEpisodes = async (entry: WatchListEntry, newAmount: number) => {
    if (!user) return;
    const delta = newAmount - entry.watchedEpisodes;
    if (delta === 0) return;

    try {
        const batch = db.batch();
        const entryRef = db.collection('users').doc(user.uid).collection('watchlist').doc(entry.id);
        const historyRef = db.collection('users').doc(user.uid).collection('history').doc();

        batch.update(entryRef, {
          watchedEpisodes: newAmount,
          updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });

        batch.set(historyRef, {
          animeId: entry.animeId,
          animeTitle: entry.title,
          episodesDelta: delta,
          timestamp: firebase.firestore.FieldValue.serverTimestamp()
        });

        await batch.commit();
    } catch (err: any) {
        setError(`UPDATE_ERROR: ${err.message}`);
    }
  };

  if (authLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-black text-accent">
        <div className="flex flex-col items-center gap-4">
            <Loader2 className="w-12 h-12 animate-spin text-accent" />
            <div className="font-mono text-sm animate-pulse uppercase tracking-[0.2em] text-accent">Matrix_Link_Establishing...</div>
        </div>
      </div>
    );
  }

  if (!user) {
    if (!showAuth) {
        return (
          <>
            <HomePage onStart={() => setShowAuth(true)} isDark={true} toggleTheme={() => {}} />
            <AmbientSound />
          </>
        );
    }

    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-4 relative overflow-hidden bg-black text-white">
        <CyberBackground />
        <AmbientSound />
        <button onClick={() => setShowAuth(false)} className="absolute top-6 left-6 z-50 text-gray-500 hover:text-accent flex items-center gap-2 font-mono text-xs transition-colors">
          <ArrowLeft className="w-4 h-4" /> <span>ABORT_SEQUENCE</span>
        </button>
        <CyberCard className="w-full max-w-md animate-slide-up">
          <div className="p-8">
            <div className="text-center mb-10">
              <div className="flex justify-center mb-6 relative">
                 <div className="absolute inset-0 bg-accent/20 blur-2xl rounded-full" />
                 <Logo className="w-24 h-24 relative z-10 drop-shadow-[0_0_10px_var(--accent-dim)] animate-pulse" />
              </div>
              <h1 className="text-3xl font-black text-white tracking-tighter mb-1"><GlitchText>ACCESS_CONTROL</GlitchText></h1>
              <p className="text-accent font-mono text-[10px] tracking-[0.2em] uppercase">Verify Identity to Proceed</p>
            </div>
            <form onSubmit={handleAuth} className="space-y-6">
              <CyberInput label="User ID / Email" type="email" required value={email} onChange={(e) => setEmail(e.target.value)} placeholder="runner@net.city" />
              <CyberInput label="Access Key / Password" type="password" required value={password} onChange={(e) => setPassword(e.target.value)} placeholder="••••••••" />
              {error && <div className="p-3 border border-cyber-pink bg-cyber-pink/10 text-cyber-pink text-xs font-mono flex items-center gap-2"><Wifi className="w-4 h-4"/> ERROR: {error}</div>}
              <CyberButton type="submit" primary className="w-full" disabled={formLoading}>
                {formLoading ? <div className="flex items-center justify-center gap-2"><Loader2 className="w-5 h-5 animate-spin" /><span>PROCESSING...</span></div> : (isSignUp ? 'Initialize_Account' : 'Jack_In')}
              </CyberButton>
            </form>
            <div className="mt-8 relative"><div className="absolute inset-0 flex items-center"><div className="w-full border-t border-gray-800"></div></div><div className="relative flex justify-center text-xs"><span className="bg-black px-2 text-gray-600 font-mono">ALTERNATE_UPLINK</span></div></div>
            <button type="button" onClick={handleGoogleLogin} disabled={formLoading} className={`mt-6 w-full py-3 bg-white hover:bg-gray-100 text-black font-sans font-bold text-sm transition-all flex items-center justify-center gap-3 uppercase tracking-wider group shadow-[0_0_15px_rgba(255,255,255,0.1)] hover:shadow-[0_0_20px_rgba(255,255,255,0.3)] ${formLoading ? 'opacity-50 cursor-not-allowed' : ''}`} style={{ clipPath: 'polygon(10px 0, 100% 0, 100% calc(100% - 10px), calc(100% - 10px) 100%, 0 100%, 0 10px)' }}>
              <svg className="w-5 h-5" viewBox="0 0 24 24">
                <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4" />
                <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853" />
                <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05" />
                <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335" />
              </svg>
              <span>Sign In with Google</span>
            </button>
            <div className="mt-8 text-center">
              <button onClick={() => setIsSignUp(!isSignUp)} className="text-xs text-accent hover:text-white font-mono hover:underline decoration-accent underline-offset-4">
                {isSignUp ? "HAS_ACCOUNT? EXECUTE LOGIN" : "NO_DATA? CREATE NEW RECORD"}
              </button>
            </div>
          </div>
        </CyberCard>
      </div>
    );
  }

  const stats = calculateStats(history, watchlist);

  return (
    <div className="min-h-screen relative pb-20 font-sans selection:bg-cyber-pink selection:text-white bg-[var(--bg-color)] text-[var(--text-color)] transition-colors duration-500">
      <CyberBackground />
      <AmbientSound />

      <header className="sticky top-0 z-40 bg-[var(--bg-color)]/80 backdrop-blur-md border-b border-[var(--border-color)]">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-3 group">
            <Logo className="w-10 h-10 hover:scale-110 transition-transform duration-300" />
            <span className="font-mono font-bold text-xl tracking-tighter text-[var(--text-color)] group-hover:text-accent transition-colors">ANI<span className="text-accent">TRACK</span></span>

            <button 
              onClick={syncData}
              className="ml-4 flex items-center gap-2 border-l border-gray-800 pl-4 h-8 group/sync"
            >
               {hasPendingWrites || isSyncing ? (
                 <div className="flex items-center gap-2 text-amber-500 animate-pulse" title="Syncing to Cloud...">
                    <RefreshCw className="w-3.5 h-3.5 animate-spin" />
                    <span className="text-[10px] font-mono font-bold hidden md:inline">UPLINKING...</span>
                 </div>
               ) : (
                 <div className="flex items-center gap-2 text-accent" title="Synchronized with Matrix">
                    <Cloud className="w-4 h-4 group-hover/sync:scale-110 transition-transform" />
                    <span className="text-[10px] font-mono font-bold hidden md:inline">SYNCHRONIZED</span>
                 </div>
               )}
            </button>
          </div>

          <div className="flex items-center gap-6">
            <div className="hidden lg:flex flex-col items-end cursor-default font-mono border-r border-gray-800 pr-6 mr-2">
                <span className="text-xs font-bold text-accent leading-none mb-1 flex items-center gap-2">
                   <UserCheck className="w-3 h-3 text-accent" /> {user.displayName || 'ANON_RUNNER'}
                </span>
                <span className="text-[9px] text-gray-500 uppercase tracking-widest">{lastSyncTime ? `LAST_SYNC: ${lastSyncTime.toLocaleTimeString()}` : 'WAITING_FOR_DATA'}</span>
            </div>

            <div className="flex items-center gap-4">
                <button onClick={() => setShowProfile(true)} className="w-10 h-10 border border-gray-700 hover:border-accent transition-all flex items-center justify-center overflow-hidden bg-black relative">
                     {user.photoURL ? <img src={user.photoURL} alt="User" className="w-full h-full object-cover opacity-80" /> : <Ghost className="w-5 h-5 text-gray-500" />}
                     <div className="absolute top-0 right-0 w-2 h-2 bg-accent border border-black rounded-full" />
                </button>
                <button onClick={handleLogout} className="p-2 text-gray-600 hover:text-red-500 transition-colors" title="Sever Connection">
                  <LogOut className="w-5 h-5" />
                </button>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 pt-10 relative z-10">
        {(error || isOffline) && (
          <div className={`mb-8 p-4 border flex items-center justify-between gap-4 animate-fade-in ${isOffline ? 'bg-amber-900/20 border-amber-500 text-amber-500' : 'bg-cyber-pink/10 border-cyber-pink text-cyber-pink'}`}>
            <div className="flex items-center gap-3">
               {isOffline ? <CloudOff className="w-6 h-6" /> : <AlertTriangle className="w-6 h-6" />}
               <div>
                  <h3 className="font-bold font-mono tracking-wider">{isOffline ? 'OFFLINE_MODE' : 'SYNC_PROTOCOL_ERROR'}</h3>
                  <p className="text-xs font-mono opacity-80">{isOffline ? 'LOCAL_CACHE_ONLY. RECONNECT TO UPLOAD.' : error}</p>
               </div>
            </div>
            <div className="flex items-center gap-2">
               {!isOffline && <CyberButton onClick={syncData} className="text-[10px] px-3 py-1">Retry_Link</CyberButton>}
               <button onClick={() => setError('')} className="p-2 hover:bg-white/10 rounded"><X className="w-5 h-5" /></button>
            </div>
          </div>
        )}

        <section className="mb-16 animate-fade-in">
          <div className="flex items-end justify-between mb-8 border-b border-[var(--border-color)] pb-4">
             <div><h2 className="text-2xl font-black text-[var(--text-color)] uppercase tracking-tight mb-1">Data Overview</h2><div className="text-[10px] font-mono text-gray-500">NEURAL_DASHBOARD</div></div>
             <button onClick={() => setShowHistory(true)} className="flex items-center gap-2 px-4 py-2 bg-white/5 border border-[var(--border-color)] hover:border-accent text-gray-400 text-xs font-mono transition-all uppercase tracking-wider">
               <History className="w-3 h-3" /> View Logs
             </button>
          </div>
          <StatsBoard stats={stats} />
        </section>

        <section className="mb-20 flex flex-col items-center">
          <div className="w-full max-w-2xl text-center mb-8">
             <h2 className="text-xl font-bold text-[var(--text-color)] uppercase tracking-widest mb-2"><GlitchText>Database Entry</GlitchText></h2>
             <div className="h-0.5 w-24 bg-accent mx-auto" />
          </div>
          <AnimeSearch onAddAnime={addAnimeToLibrary} watchlist={watchlist} />
        </section>

        <section>
          <div className="flex flex-col sm:flex-row items-end justify-between mb-8 gap-4 border-b border-[var(--border-color)] pb-4">
            <div className="flex items-center gap-4">
                <h2 className="text-3xl font-black text-[var(--text-color)] flex items-center gap-3 uppercase">MEMORY BANK <span className="text-lg font-mono font-normal text-accent border border-accent px-2 py-0.5">{watchlist.length}</span></h2>
                <button onClick={syncData} disabled={isSyncing} className={`p-2 border border-gray-800 text-gray-600 hover:text-accent hover:border-accent transition-all rounded-full ${isSyncing ? 'animate-spin' : ''}`} title="Force Refresh from Cloud">
                   <RefreshCw className="w-4 h-4" />
                </button>
            </div>
            <div className="flex items-center gap-3">
              <span className="text-[10px] font-mono text-gray-500 uppercase">Sort_Type:</span>
              <div className="flex gap-1">
                <button onClick={() => setSortType('updated')} className={`px-3 py-1 text-[10px] font-mono border ${sortType === 'updated' ? 'bg-accent/20 border-accent text-accent' : 'border-gray-800 text-gray-500 hover:border-gray-600'}`}>Recent</button>
                <button onClick={() => setSortType('title')} className={`px-3 py-1 text-[10px] font-mono border ${sortType === 'title' ? 'bg-accent/20 border-accent text-accent' : 'border-gray-800 text-gray-500 hover:border-gray-600'}`}>Alpha</button>
              </div>
            </div>
          </div>

          {watchlist.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-24 border border-dashed border-gray-800 bg-white/5">
              <Ghost className="w-16 h-16 text-gray-800 mb-4" />
              <p className="font-mono text-gray-500 text-lg uppercase">Memory Void</p>
              <p className="font-mono text-gray-700 text-[10px] mt-2 tracking-widest uppercase">Initializing neural link... search to populate</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 sm:gap-6 lg:gap-8">
              {sortedWatchlist.map((entry) => (
                <AnimeCard 
                  key={entry.id} 
                  entry={entry} 
                  onUpdateEpisodes={updateEpisodes} 
                  onRemove={(id) => {
                    if (window.confirm("WARNING: Confirm deletion of database entry.")) {
                      db.collection('users').doc(user.uid).collection('watchlist').doc(id).delete();
                    }
                  }} 
                />
              ))}
            </div>
          )}
        </section>
      </main>

      {showProfile && user && <UserProfile user={user} stats={stats} animeCount={watchlist.length} themeSettings={themeSettings} onClose={() => setShowProfile(false)} />}
      {showHistory && <HistoryModal history={history} watchlist={watchlist} onClose={() => setShowHistory(false)} onUpdate={async (id, data) => {
        await db.collection('users').doc(user.uid).collection('history').doc(id).update(data);
      }} onDelete={async (id) => {
        await db.collection('users').doc(user.uid).collection('history').doc(id).delete();
      }} />}
    </div>
  );
};

export default App;

export interface Anime {
  mal_id: number;
  title: string;
  images: {
    jpg: {
      large_image_url: string;
      image_url: string;
    };
  };
  episodes: number | null;
  genres: { name: string }[];
  score?: number;
  synopsis?: string;
}

export interface ThemeSettings {
  mode: 'dark' | 'light';
  accentColor: string;
  accentName: string;
}

export interface WatchListEntry {
  id: string; // Firestore ID
  animeId: number;
  title: string;
  imageUrl: string;
  totalEpisodes: number | null;
  watchedEpisodes: number;
  genres: string[];
  updatedAt: string; // ISO String
  pending?: boolean; // True if data has not yet synced to the cloud
  score?: number;
  synopsis?: string;
}

export interface WatchHistoryItem {
  id?: string;
  animeId: number;
  animeTitle?: string;
  episodesDelta: number;
  timestamp: string; // ISO String
}

export interface UserStats {
  todayMinutes: number;
  monthMinutes: number;
  yearMinutes: number;
  lifetimeMinutes: number;
}

import React, { useState, useEffect, useMemo } from 'react';
import firebase from 'firebase/compat/app';
import { auth, db, googleProvider } from './firebase';
import { Anime, WatchListEntry, WatchHistoryItem, ThemeSettings } from './types';
import { calculateStats } from './services/statsService';
import { AnimeSearch } from './components/AnimeSearch';
import { AnimeCard } from './components/AnimeCard';
import { StatsBoard } from './components/StatsBoard';
import { UserProfile } from './components/UserProfile';
import { HistoryModal } from './components/HistoryModal';
import { HomePage } from './components/HomePage';
import { CyberBackground, CyberButton, CyberInput, CyberCard, GlitchText } from './components/CyberUI';
import { Logo } from './components/Logo';
import { AmbientSound } from './components/AmbientSound';
import { Loader2, LogOut, History, ArrowLeft, Ghost, Wifi, AlertTriangle, X, CloudOff, Cloud, RefreshCw, UserCheck, Zap, Palette } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<firebase.User | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [watchlist, setWatchlist] = useState<WatchListEntry[]>([]);
  const [history, setHistory] = useState<WatchHistoryItem[]>([]);
  const [sortType, setSortType] = useState<'updated' | 'title'>('updated');
  const [showProfile, setShowProfile] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [isOffline, setIsOffline] = useState(!navigator.onLine);
  const [hasPendingWrites, setHasPendingWrites] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSyncTime, setLastSyncTime] = useState<Date | null>(null);
  const [themeSettings, setThemeSettings] = useState<ThemeSettings | null>(null);

  // Auth Form State
  const [showAuth, setShowAuth] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isSignUp, setIsSignUp] = useState(false);
  const [error, setError] = useState('');
  const [formLoading, setFormLoading] = useState(false);

  // Apply theme to document with safety checks for hex colors
  useEffect(() => {
    const root = document.documentElement;
    if (themeSettings) {
      root.style.setProperty('--accent-color', themeSettings.accentColor);

      // Calculate a dim version for glow effects
      try {
        const hex = themeSettings.accentColor.replace('#', '');
        const r = parseInt(hex.substring(0, 2), 16);
        const g = parseInt(hex.substring(2, 4), 16);
        const b = parseInt(hex.substring(4, 6), 16);
        root.style.setProperty('--accent-dim', `rgba(${r}, ${g}, ${b}, 0.2)`);
      } catch (e) {
        root.style.setProperty('--accent-dim', `rgba(0, 255, 159, 0.2)`);
      }

      if (themeSettings.mode === 'light') {
        root.classList.add('light');
        root.classList.remove('dark');
      } else {
        root.classList.add('dark');
        root.classList.remove('light');
      }
    } else {
      // Default fallback
      root.classList.add('dark');
      root.classList.remove('light');
      root.style.setProperty('--accent-color', '#00ff9f');
      root.style.setProperty('--accent-dim', 'rgba(0, 255, 159, 0.2)');
    }
  }, [themeSettings]);

  // Network Listener
  useEffect(() => {
    const handleOnline = () => setIsOffline(false);
    const handleOffline = () => setIsOffline(true);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Auth Listener
  useEffect(() => {
    const unsubscribe = auth.onAuthStateChanged((currentUser) => {
      setUser(currentUser);
      setAuthLoading(false);
      if (currentUser) {
        setShowAuth(false);
      }
    });
    return () => unsubscribe();
  }, []);

  // Theme Listener
  useEffect(() => {
    if (!user) return;
    const unsub = db.collection('users').doc(user.uid).onSnapshot((doc) => {
      if (doc.exists) {
        const data = doc.data();
        if (data?.theme) {
          setThemeSettings(data.theme);
        }
      }
    });
    return () => unsub();
  }, [user]);

  // Helper to convert Firestore timestamp to ISO string
  const formatFirestoreDate = (val: any): string => {
    if (!val) return new Date().toISOString();
    if (typeof val.toDate === 'function') return val.toDate().toISOString();
    return val;
  };

  const syncData = async () => {
    if (!user) return;
    setIsSyncing(true);
    setError('');

    try {
      const watchlistRef = db.collection('users').doc(user.uid).collection('watchlist');
      const historyRef = db.collection('users').doc(user.uid).collection('history');

      const [wSnap, hSnap] = await Promise.all([
        watchlistRef.get({ source: 'server' }),
        historyRef.get({ source: 'server' })
      ]);

      const wList = wSnap.docs.map(doc => ({ 
        id: doc.id, 
        ...doc.data(),
        updatedAt: formatFirestoreDate(doc.get('updatedAt'))
      })) as WatchListEntry[];

      const hList = hSnap.docs.map(doc => ({ 
        id: doc.id, 
        ...doc.data(),
        timestamp: formatFirestoreDate(doc.get('timestamp'))
      })) as WatchHistoryItem[];

      setWatchlist(wList);
      setHistory(hList);
      setLastSyncTime(new Date());
    } catch (err: any) {
      console.warn("Server sync attempt failed:", err);
      setError("SYNC_LINK_TIMEOUT: Retrying with local cache.");
    } finally {
      setIsSyncing(false);
    }
  };

  useEffect(() => {
    if (!user) {
      setWatchlist([]);
      setHistory([]);
      return;
    }

    const userRef = db.collection('users').doc(user.uid);

    const unsubWatchlist = userRef.collection('watchlist').onSnapshot({ includeMetadataChanges: true }, (snapshot) => {
      const list = snapshot.docs.map(doc => {
        const data = doc.data();
        return {
          id: doc.id,
          ...data,
          updatedAt: formatFirestoreDate(data.updatedAt),
          pending: doc.metadata.hasPendingWrites
        };
      }) as WatchListEntry[];

      setWatchlist(list);
      setHasPendingWrites(snapshot.metadata.hasPendingWrites);
      if (!snapshot.metadata.hasPendingWrites) {
        setLastSyncTime(new Date());
      }
    }, (err) => {
        console.error("Watchlist Listener Error:", err);
        setError(`DATABASE_STREAM_ERR: ${err.message}`);
    });

    const unsubHistory = userRef.collection('history').onSnapshot((snapshot) => {
      const hist = snapshot.docs.map(doc => {
        const data = doc.data();
        return {
          id: doc.id,
          ...data,
          timestamp: formatFirestoreDate(data.timestamp)
        };
      }) as WatchHistoryItem[];
      setHistory(hist);
    });

    const unsubSync = db.onSnapshotsInSync(() => {
      setHasPendingWrites(false);
    });

    return () => {
      unsubWatchlist();
      unsubHistory();
      unsubSync();
    };
  }, [user]);

  const sortedWatchlist = useMemo(() => {
    const data = [...watchlist];
    if (sortType === 'updated') {
      return data.sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime());
    } else {
      return data.sort((a, b) => a.title.localeCompare(b.title));
    }
  }, [watchlist, sortType]);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setFormLoading(true);
    try {
      if (isSignUp) {
        await auth.createUserWithEmailAndPassword(email, password);
      } else {
        await auth.signInWithEmailAndPassword(email, password);
      }
    } catch (err: any) {
      setError(err.message.replace('Firebase: ', ''));
    } finally {
      setFormLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
    setError('');
    setFormLoading(true);
    try {
      await auth.signInWithPopup(googleProvider);
    } catch (err: any) {
      setError(err.message.replace('Firebase: ', ''));
      setFormLoading(false);
    }
  };

  const handleLogout = () => {
      setError('');
      auth.signOut();
  };

  const addAnimeToLibrary = async (anime: Anime, initialWatched: number) => {
    if (!user) return;
    try {
        const batch = db.batch();
        const watchlistRef = db.collection('users').doc(user.uid).collection('watchlist').doc();

        const newEntry = {
          animeId: anime.mal_id,
          title: anime.title,
          imageUrl: anime.images.jpg.large_image_url,
          totalEpisodes: anime.episodes,
          watchedEpisodes: initialWatched,
          genres: anime.genres.map(g => g.name),
          score: anime.score || null,
          synopsis: anime.synopsis || "",
          updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        };

        batch.set(watchlistRef, newEntry);

        if (initialWatched > 0) {
            const historyRef = db.collection('users').doc(user.uid).collection('history').doc();
            batch.set(historyRef, {
                animeId: anime.mal_id,
                animeTitle: anime.title,
                episodesDelta: initialWatched,
                timestamp: firebase.firestore.FieldValue.serverTimestamp()
            });
        }

        await batch.commit();
    } catch (err: any) {
        setError(`WRITE_ERROR: ${err.message}`);
    }
  };

  const updateEpisodes = async (entry: WatchListEntry, newAmount: number) => {
    if (!user) return;
    const delta = newAmount - entry.watchedEpisodes;
    if (delta === 0) return;

    try {
        const batch = db.batch();
        const entryRef = db.collection('users').doc(user.uid).collection('watchlist').doc(entry.id);
        const historyRef = db.collection('users').doc(user.uid).collection('history').doc();

        batch.update(entryRef, {
          watchedEpisodes: newAmount,
          updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });

        batch.set(historyRef, {
          animeId: entry.animeId,
          animeTitle: entry.title,
          episodesDelta: delta,
          timestamp: firebase.firestore.FieldValue.serverTimestamp()
        });

        await batch.commit();
    } catch (err: any) {
        setError(`UPDATE_ERROR: ${err.message}`);
    }
  };

  if (authLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-black text-accent">
        <div className="flex flex-col items-center gap-4">
            <Loader2 className="w-12 h-12 animate-spin text-accent" />
            <div className="font-mono text-sm animate-pulse uppercase tracking-[0.2em] text-accent">Matrix_Link_Establishing...</div>
        </div>
      </div>
    );
  }

  if (!user) {
    if (!showAuth) {
        return (
          <>
            <HomePage onStart={() => setShowAuth(true)} isDark={true} toggleTheme={() => {}} />
            <AmbientSound />
          </>
        );
    }

    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-4 relative overflow-hidden bg-black text-white">
        <CyberBackground />
        <AmbientSound />
        <button onClick={() => setShowAuth(false)} className="absolute top-6 left-6 z-50 text-gray-500 hover:text-accent flex items-center gap-2 font-mono text-xs transition-colors">
          <ArrowLeft className="w-4 h-4" /> <span>ABORT_SEQUENCE</span>
        </button>
        <CyberCard className="w-full max-w-md animate-slide-up">
          <div className="p-8">
            <div className="text-center mb-10">
              <div className="flex justify-center mb-6 relative">
                 <div className="absolute inset-0 bg-accent/20 blur-2xl rounded-full" />
                 <Logo className="w-24 h-24 relative z-10 drop-shadow-[0_0_10px_var(--accent-dim)] animate-pulse" />
              </div>
              <h1 className="text-3xl font-black text-white tracking-tighter mb-1"><GlitchText>ACCESS_CONTROL</GlitchText></h1>
              <p className="text-accent font-mono text-[10px] tracking-[0.2em] uppercase">Verify Identity to Proceed</p>
            </div>
            <form onSubmit={handleAuth} className="space-y-6">
              <CyberInput label="User ID / Email" type="email" required value={email} onChange={(e) => setEmail(e.target.value)} placeholder="runner@net.city" />
              <CyberInput label="Access Key / Password" type="password" required value={password} onChange={(e) => setPassword(e.target.value)} placeholder="••••••••" />
              {error && <div className="p-3 border border-cyber-pink bg-cyber-pink/10 text-cyber-pink text-xs font-mono flex items-center gap-2"><Wifi className="w-4 h-4"/> ERROR: {error}</div>}
              <CyberButton type="submit" primary className="w-full" disabled={formLoading}>
                {formLoading ? <div className="flex items-center justify-center gap-2"><Loader2 className="w-5 h-5 animate-spin" /><span>PROCESSING...</span></div> : (isSignUp ? 'Initialize_Account' : 'Jack_In')}
              </CyberButton>
            </form>
            <div className="mt-8 relative"><div className="absolute inset-0 flex items-center"><div className="w-full border-t border-gray-800"></div></div><div className="relative flex justify-center text-xs"><span className="bg-black px-2 text-gray-600 font-mono">ALTERNATE_UPLINK</span></div></div>
            <button type="button" onClick={handleGoogleLogin} disabled={formLoading} className={`mt-6 w-full py-3 bg-white hover:bg-gray-100 text-black font-sans font-bold text-sm transition-all flex items-center justify-center gap-3 uppercase tracking-wider group shadow-[0_0_15px_rgba(255,255,255,0.1)] hover:shadow-[0_0_20px_rgba(255,255,255,0.3)] ${formLoading ? 'opacity-50 cursor-not-allowed' : ''}`} style={{ clipPath: 'polygon(10px 0, 100% 0, 100% calc(100% - 10px), calc(100% - 10px) 100%, 0 100%, 0 10px)' }}>
              <svg className="w-5 h-5" viewBox="0 0 24 24">
                <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4" />
                <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853" />
                <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05" />
                <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335" />
              </svg>
              <span>Sign In with Google</span>
            </button>
            <div className="mt-8 text-center">
              <button onClick={() => setIsSignUp(!isSignUp)} className="text-xs text-accent hover:text-white font-mono hover:underline decoration-accent underline-offset-4">
                {isSignUp ? "HAS_ACCOUNT? EXECUTE LOGIN" : "NO_DATA? CREATE NEW RECORD"}
              </button>
            </div>
          </div>
        </CyberCard>
      </div>
    );
  }

  const stats = calculateStats(history, watchlist);

  return (
    <div className="min-h-screen relative pb-20 font-sans selection:bg-cyber-pink selection:text-white bg-[var(--bg-color)] text-[var(--text-color)] transition-colors duration-500">
      <CyberBackground />
      <AmbientSound />

      <header className="sticky top-0 z-40 bg-[var(--bg-color)]/80 backdrop-blur-md border-b border-[var(--border-color)]">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-3 group">
            <Logo className="w-10 h-10 hover:scale-110 transition-transform duration-300" />
            <span className="font-mono font-bold text-xl tracking-tighter text-[var(--text-color)] group-hover:text-accent transition-colors">ANI<span className="text-accent">TRACK</span></span>

            <button 
              onClick={syncData}
              className="ml-4 flex items-center gap-2 border-l border-gray-800 pl-4 h-8 group/sync"
            >
               {hasPendingWrites || isSyncing ? (
                 <div className="flex items-center gap-2 text-amber-500 animate-pulse" title="Syncing to Cloud...">
                    <RefreshCw className="w-3.5 h-3.5 animate-spin" />
                    <span className="text-[10px] font-mono font-bold hidden md:inline">UPLINKING...</span>
                 </div>
               ) : (
                 <div className="flex items-center gap-2 text-accent" title="Synchronized with Matrix">
                    <Cloud className="w-4 h-4 group-hover/sync:scale-110 transition-transform" />
                    <span className="text-[10px] font-mono font-bold hidden md:inline">SYNCHRONIZED</span>
                 </div>
               )}
            </button>
          </div>

          <div className="flex items-center gap-6">
            <div className="hidden lg:flex flex-col items-end cursor-default font-mono border-r border-gray-800 pr-6 mr-2">
                <span className="text-xs font-bold text-accent leading-none mb-1 flex items-center gap-2">
                   <UserCheck className="w-3 h-3 text-accent" /> {user.displayName || 'ANON_RUNNER'}
                </span>
                <span className="text-[9px] text-gray-500 uppercase tracking-widest">{lastSyncTime ? `LAST_SYNC: ${lastSyncTime.toLocaleTimeString()}` : 'WAITING_FOR_DATA'}</span>
            </div>

            <div className="flex items-center gap-4">
                <button onClick={() => setShowProfile(true)} className="w-10 h-10 border border-gray-700 hover:border-accent transition-all flex items-center justify-center overflow-hidden bg-black relative">
                     {user.photoURL ? <img src={user.photoURL} alt="User" className="w-full h-full object-cover opacity-80" /> : <Ghost className="w-5 h-5 text-gray-500" />}
                     <div className="absolute top-0 right-0 w-2 h-2 bg-accent border border-black rounded-full" />
                </button>
                <button onClick={handleLogout} className="p-2 text-gray-600 hover:text-red-500 transition-colors" title="Sever Connection">
                  <LogOut className="w-5 h-5" />
                </button>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 pt-10 relative z-10">
        {(error || isOffline) && (
          <div className={`mb-8 p-4 border flex items-center justify-between gap-4 animate-fade-in ${isOffline ? 'bg-amber-900/20 border-amber-500 text-amber-500' : 'bg-cyber-pink/10 border-cyber-pink text-cyber-pink'}`}>
            <div className="flex items-center gap-3">
               {isOffline ? <CloudOff className="w-6 h-6" /> : <AlertTriangle className="w-6 h-6" />}
               <div>
                  <h3 className="font-bold font-mono tracking-wider">{isOffline ? 'OFFLINE_MODE' : 'SYNC_PROTOCOL_ERROR'}</h3>
                  <p className="text-xs font-mono opacity-80">{isOffline ? 'LOCAL_CACHE_ONLY. RECONNECT TO UPLOAD.' : error}</p>
               </div>
            </div>
            <div className="flex items-center gap-2">
               {!isOffline && <CyberButton onClick={syncData} className="text-[10px] px-3 py-1">Retry_Link</CyberButton>}
               <button onClick={() => setError('')} className="p-2 hover:bg-white/10 rounded"><X className="w-5 h-5" /></button>
            </div>
          </div>
        )}

        <section className="mb-16 animate-fade-in">
          <div className="flex items-end justify-between mb-8 border-b border-[var(--border-color)] pb-4">
             <div><h2 className="text-2xl font-black text-[var(--text-color)] uppercase tracking-tight mb-1">Data Overview</h2><div className="text-[10px] font-mono text-gray-500">NEURAL_DASHBOARD</div></div>
             <button onClick={() => setShowHistory(true)} className="flex items-center gap-2 px-4 py-2 bg-white/5 border border-[var(--border-color)] hover:border-accent text-gray-400 text-xs font-mono transition-all uppercase tracking-wider">
               <History className="w-3 h-3" /> View Logs
             </button>
          </div>
          <StatsBoard stats={stats} />
        </section>

        <section className="mb-20 flex flex-col items-center">
          <div className="w-full max-w-2xl text-center mb-8">
             <h2 className="text-xl font-bold text-[var(--text-color)] uppercase tracking-widest mb-2"><GlitchText>Database Entry</GlitchText></h2>
             <div className="h-0.5 w-24 bg-accent mx-auto" />
          </div>
          <AnimeSearch onAddAnime={addAnimeToLibrary} watchlist={watchlist} />
        </section>

        <section>
          <div className="flex flex-col sm:flex-row items-end justify-between mb-8 gap-4 border-b border-[var(--border-color)] pb-4">
            <div className="flex items-center gap-4">
                <h2 className="text-3xl font-black text-[var(--text-color)] flex items-center gap-3 uppercase">MEMORY BANK <span className="text-lg font-mono font-normal text-accent border border-accent px-2 py-0.5">{watchlist.length}</span></h2>
                <button onClick={syncData} disabled={isSyncing} className={`p-2 border border-gray-800 text-gray-600 hover:text-accent hover:border-accent transition-all rounded-full ${isSyncing ? 'animate-spin' : ''}`} title="Force Refresh from Cloud">
                   <RefreshCw className="w-4 h-4" />
                </button>
            </div>
            <div className="flex items-center gap-3">
              <span className="text-[10px] font-mono text-gray-500 uppercase">Sort_Type:</span>
              <div className="flex gap-1">
                <button onClick={() => setSortType('updated')} className={`px-3 py-1 text-[10px] font-mono border ${sortType === 'updated' ? 'bg-accent/20 border-accent text-accent' : 'border-gray-800 text-gray-500 hover:border-gray-600'}`}>Recent</button>
                <button onClick={() => setSortType('title')} className={`px-3 py-1 text-[10px] font-mono border ${sortType === 'title' ? 'bg-accent/20 border-accent text-accent' : 'border-gray-800 text-gray-500 hover:border-gray-600'}`}>Alpha</button>
              </div>
            </div>
          </div>

          {watchlist.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-24 border border-dashed border-gray-800 bg-white/5">
              <Ghost className="w-16 h-16 text-gray-800 mb-4" />
              <p className="font-mono text-gray-500 text-lg uppercase">Memory Void</p>
              <p className="font-mono text-gray-700 text-[10px] mt-2 tracking-widest uppercase">Initializing neural link... search to populate</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 sm:gap-6 lg:gap-8">
              {sortedWatchlist.map((entry) => (
                <AnimeCard 
                  key={entry.id} 
                  entry={entry} 
                  onUpdateEpisodes={updateEpisodes} 
                  onRemove={(id) => {
                    if (window.confirm("WARNING: Confirm deletion of database entry.")) {
                      db.collection('users').doc(user.uid).collection('watchlist').doc(id).delete();
                    }
                  }} 
                />
              ))}
            </div>
          )}
        </section>
      </main>

      {showProfile && user && <UserProfile user={user} stats={stats} animeCount={watchlist.length} themeSettings={themeSettings} onClose={() => setShowProfile(false)} />}
      {showHistory && <HistoryModal history={history} watchlist={watchlist} onClose={() => setShowHistory(false)} onUpdate={async (id, data) => {
        await db.collection('users').doc(user.uid).collection('history').doc(id).update(data);
      }} onDelete={async (id) => {
        await db.collection('users').doc(user.uid).collection('history').doc(id).delete();
      }} />}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Plus, Minus, Trash2, Activity, RefreshCw, Star, ChevronDown, ChevronUp, Database } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { WatchListEntry } from '../types';
import { GENRE_COLORS } from '../constants';

interface AnimeCardProps {
  entry: WatchListEntry;
  onUpdateEpisodes: (entry: WatchListEntry, newAmount: number) => void;
  onRemove: (id: string) => void;
}

export const AnimeCard: React.FC<AnimeCardProps> = ({ entry, onUpdateEpisodes, onRemove }) => {
  const [loading, setLoading] = useState(false);
  const [isUpdating, setIsUpdating] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);

  // Trigger pulse effect when watched episodes change locally or via sync
  useEffect(() => {
    setIsUpdating(true);
    const timer = setTimeout(() => setIsUpdating(false), 800);
    return () => clearTimeout(timer);
  }, [entry.watchedEpisodes, entry.pending]);

  const handleUpdate = async (e: React.MouseEvent, delta: number) => {
    e.stopPropagation(); // Prevent card expansion when clicking controls
    const newAmount = entry.watchedEpisodes + delta;
    if (newAmount < 0) return;
    if (entry.totalEpisodes && newAmount > entry.totalEpisodes) return;

    setLoading(true);
    await onUpdateEpisodes(entry, newAmount);
    setLoading(false);
  };

  const handleRemove = (e: React.MouseEvent) => {
    e.stopPropagation();
    onRemove(entry.id);
  };

  const progress = entry.totalEpisodes 
    ? (entry.watchedEpisodes / entry.totalEpisodes) * 100 
    : 0;

  return (
    <div 
        onClick={() => setIsExpanded(!isExpanded)}
        className={`group relative bg-[var(--card-bg)] border transition-all duration-500 flex flex-col h-fit cursor-pointer animate-slide-up overflow-hidden ${
          entry.pending ? 'border-amber-500/50 shadow-[0_0_15px_rgba(245,158,11,0.1)]' : 'border-white/10 hover:border-accent'
        } ${isExpanded ? 'ring-1 ring-accent/30 shadow-[0_0_20px_var(--accent-dim)]' : ''}`}
        style={{ clipPath: 'polygon(15px 0, 100% 0, 100% calc(100% - 15px), calc(100% - 15px) 100%, 0 100%, 0 15px)' }}
    >
      {/* Image Section */}
      <div className="relative aspect-[16/9] overflow-hidden border-b border-white/10">
        <img 
          src={entry.imageUrl} 
          alt={entry.title} 
          className={`w-full h-full object-cover transition-all duration-500 group-hover:scale-105 ${entry.pending ? 'grayscale opacity-60' : 'grayscale group-hover:grayscale-0'} ${isExpanded ? 'grayscale-0 scale-105' : ''}`}
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black via-black/50 to-transparent" />

        {/* Title Overlay */}
        <div className="absolute bottom-0 left-0 p-4 w-full">
            <h3 className={`font-mono font-bold text-lg leading-tight line-clamp-1 drop-shadow-[0_2px_4px_rgba(0,0,0,0.8)] transition-colors ${entry.pending ? 'text-amber-500' : 'text-white'}`}>
                {entry.title}
            </h3>
            <div className={`h-[2px] mt-2 transition-all duration-500 ${entry.pending ? 'w-1/2 bg-amber-500 animate-pulse' : isExpanded ? 'w-full bg-accent' : 'w-10 bg-accent group-hover:w-full'}`} />
        </div>

        {/* Score Badge */}
        {entry.score && (
          <div className="absolute top-2 left-2 flex items-center gap-1 px-2 py-0.5 bg-black/70 border border-accent/40 backdrop-blur-sm">
             <Star className="w-3 h-3 text-yellow-400 fill-yellow-400" />
             <span className="text-[10px] font-mono font-bold text-accent">{entry.score}</span>
          </div>
        )}

        {/* Delete Button */}
        <button 
          onClick={handleRemove}
          className="absolute top-0 right-0 p-2 bg-black/60 text-gray-500 hover:text-red-500 hover:bg-black transition-colors backdrop-blur-sm z-10"
        >
          <Trash2 className="w-4 h-4" />
        </button>

        {/* Sync Indicator for Pending Writes */}
        {entry.pending && (
          <div className="absolute top-2 right-12 p-1.5 bg-amber-500/20 text-amber-500 backdrop-blur-sm flex items-center gap-1 font-mono text-[9px] border border-amber-500/50 z-10">
             <RefreshCw className="w-2.5 h-2.5 animate-spin" />
             <span className="tracking-tighter">OFFLINE_STUB</span>
          </div>
        )}
      </div>

      {/* Content Section */}
      <div className="p-4 flex flex-col backdrop-blur-sm relative">
        {/* Background update flash */}
        <div className={`absolute inset-0 bg-accent/5 pointer-events-none transition-opacity duration-500 ${isUpdating && !entry.pending ? 'opacity-100' : 'opacity-0'}`} />

        <div className="flex flex-wrap gap-1 mb-4 relative z-10">
          {entry.genres.slice(0, 3).map((genre) => {
             const colorClass = GENRE_COLORS[genre] || GENRE_COLORS['Default'];
             return (
              <span key={genre} className={`text-[9px] px-1.5 py-0.5 font-mono uppercase tracking-wider ${colorClass}`}>
                {genre}
              </span>
             );
          })}
        </div>

        <div className="relative z-10">
          {/* Progress Info */}
          <div className="flex justify-between items-end mb-2 font-mono text-xs">
            <span className={`transition-colors flex items-center gap-1 ${entry.pending ? 'text-amber-500/70' : 'text-gray-500 group-hover:text-accent'} ${isExpanded ? 'text-accent' : ''}`}>
               <Activity className="w-3 h-3" /> PROGRESS
            </span>
            <span className={entry.pending ? 'text-amber-500' : 'text-[var(--text-color)]'}>
              {entry.watchedEpisodes} <span className="text-gray-500">/ {entry.totalEpisodes || '?'}</span>
            </span>
          </div>

          {/* Progress Bar */}
          <div className={`w-full bg-gray-900/40 h-1.5 mb-4 border overflow-hidden rounded-sm transition-colors ${entry.pending ? 'border-amber-900/50' : 'border-gray-800'}`}>
            <div 
              className={`h-full relative transition-all duration-700 ease-[cubic-bezier(0.4,0,0.2,1)] ${
                entry.pending 
                  ? 'bg-amber-600 shadow-[0_0_10px_#d97706]' 
                  : isUpdating 
                    ? 'bg-accent shadow-[0_0_20px_var(--accent-color)] brightness-125' 
                    : 'bg-accent shadow-[0_0_5px_var(--accent-dim)]'
              }`}
              style={{ width: `${entry.totalEpisodes ? progress : 100}%` }}
            >
                <div className={`absolute top-0 right-0 h-full w-1 bg-white opacity-50 ${entry.pending ? 'animate-pulse' : ''}`} />
            </div>
          </div>

          {/* Controls */}
          <div className="flex items-center justify-between gap-2">
            <button
              onClick={(e) => handleUpdate(e, -1)}
              disabled={loading || entry.watchedEpisodes <= 0}
              className="p-1.5 border border-gray-800 text-gray-500 hover:border-cyber-pink hover:text-cyber-pink hover:shadow-[0_0_10px_#ff0055] transition-all disabled:opacity-30 disabled:hover:border-gray-800"
            >
              <Minus className="w-4 h-4" />
            </button>

            <div className="flex flex-col items-center">
              <span className={`text-[10px] font-mono transition-colors ${entry.pending ? 'text-amber-500/50' : 'text-gray-500'}`}>
                {entry.watchedEpisodes * 24}m
              </span>
            </div>

            <button
              onClick={(e) => handleUpdate(e, 1)}
              disabled={loading || (entry.totalEpisodes !== null && entry.watchedEpisodes >= entry.totalEpisodes)}
              className="p-1.5 border border-gray-800 text-gray-500 hover:border-accent hover:text-accent hover:shadow-[0_0_10px_var(--accent-dim)] transition-all disabled:opacity-30 disabled:hover:border-gray-800"
            >
              <Plus className="w-4 h-4" />
            </button>
          </div>
        </div>

        {/* Collapsible Details */}
        <AnimatePresence>
          {isExpanded && (
            <motion.div
              initial={{ height: 0, opacity: 0 }}
              animate={{ height: 'auto', opacity: 1 }}
              exit={{ height: 0, opacity: 0 }}
              transition={{ duration: 0.3, ease: 'easeInOut' }}
              className="overflow-hidden mt-6 border-t border-white/10 pt-4"
            >
               <div className="flex items-center gap-2 mb-2 text-accent">
                 <Database className="w-3.5 h-3.5" />
                 <span className="text-[10px] font-mono font-bold tracking-widest uppercase">Memory_Extract</span>
               </div>

               {entry.synopsis ? (
                 <p className="text-[11px] font-sans leading-relaxed text-gray-400 line-clamp-6 italic">
                   {entry.synopsis}
                 </p>
               ) : (
                 <p className="text-[10px] font-mono text-gray-600 uppercase italic">
                   No synopsis data linked.
                 </p>
               )}

               <div className="mt-4 flex justify-center">
                 <button className="text-[9px] font-mono text-gray-600 hover:text-accent transition-colors uppercase tracking-widest flex items-center gap-1">
                   Click to Retract <ChevronUp className="w-3 h-3" />
                 </button>
               </div>
            </motion.div>
          )}
        </AnimatePresence>

        {!isExpanded && (
          <div className="mt-2 flex justify-center opacity-0 group-hover:opacity-40 transition-opacity">
            <ChevronDown className="w-4 h-4 text-gray-500" />
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Search, Plus, Loader2, X, WifiOff, Hourglass, AlertTriangle, Sparkles, Database, BookmarkCheck, Filter, ChevronRight } from 'lucide-react';
import { searchAnime } from '../services/jikanService';
import { getAnimeRecommendations } from '../services/geminiService';
import { Anime, WatchListEntry } from '../types';
import { CyberInput, CyberButton, CyberCard, GlitchText } from './CyberUI';

interface AnimeSearchProps {
  onAddAnime: (anime: Anime, watched: number) => void;
  watchlist: WatchListEntry[];
}

export const AnimeSearch: React.FC<AnimeSearchProps> = ({ onAddAnime, watchlist }) => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<Anime[]>([]);
  const [loading, setLoading] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedGenre, setSelectedGenre] = useState<string>('ALL');

  // AI State
  const [showAiModal, setShowAiModal] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);
  const [aiRecommendations, setAiRecommendations] = useState<string>('');

  // Modal State
  const [selectedAnime, setSelectedAnime] = useState<Anime | null>(null);
  const [watchedInput, setWatchedInput] = useState<string>('');

  const searchContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setTimeout(async () => {
      if (query.length > 2) {
        setLoading(true);
        setError(null);
        setSelectedGenre('ALL');
        try {
          const data = await searchAnime(query);
          setResults(data);
          setShowResults(true);
        } catch (err: any) {
          setResults([]);
          setError(err.message || "Failed to fetch results");
          setShowResults(true);
        } finally {
          setLoading(false);
        }
      } else {
        setResults([]);
        setShowResults(false);
        setError(null);
      }
    }, 500);

    return () => clearTimeout(timer);
  }, [query]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (searchContainerRef.current && !searchContainerRef.current.contains(event.target as Node)) {
        setShowResults(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Compute available genres and their counts from the raw search results
  const genreData = useMemo(() => {
    const counts: Record<string, number> = {};
    results.forEach(anime => {
      anime.genres.forEach(g => {
        counts[g.name] = (counts[g.name] || 0) + 1;
      });
    });

    const sortedGenres = Object.entries(counts)
      .sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]))
      .map(([name, count]) => ({ name, count }));

    return [{ name: 'ALL', count: results.length }, ...sortedGenres];
  }, [results]);

  // Apply the selected genre filter to the search results
  const filteredResults = useMemo(() => {
    if (selectedGenre === 'ALL') return results;
    return results.filter(anime => 
      anime.genres.some(g => g.name === selectedGenre)
    );
  }, [results, selectedGenre]);

  const handleInitiateAdd = (anime: Anime) => {
    if (watchlist.some(w => w.animeId === anime.mal_id)) return;
    setSelectedAnime(anime);
    setWatchedInput('0');
    setShowResults(false);
  };

  const handleConfirmAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedAnime) return;

    let watched = parseInt(watchedInput, 10);
    if (isNaN(watched) || watched < 0) watched = 0;

    if (selectedAnime.episodes && watched > selectedAnime.episodes) {
      watched = selectedAnime.episodes;
    }

    onAddAnime(selectedAnime, watched);
    setSelectedAnime(null);
    setWatchedInput('');
    setQuery('');
  };

  const handleAiRecommend = async () => {
    setShowAiModal(true);
    setAiLoading(true);
    setAiRecommendations('');
    try {
      const titles = watchlist.map(w => w.title);
      const recs = await getAnimeRecommendations(titles);
      setAiRecommendations(recs);
    } catch (err) {
      setAiRecommendations("Neural link failed to generate suggestions.");
    } finally {
      setAiLoading(false);
    }
  };

  const getErrorConfig = (msg: string) => {
    if (msg.includes("Network:")) return { icon: WifiOff, text: msg.replace("Network:", "").trim(), color: "text-amber-500" };
    if (msg.includes("RateLimit:")) return { icon: Hourglass, text: "Uplink congested. Wait...", color: "text-orange-500" };
    return { icon: AlertTriangle, text: msg.replace("Error:", "").trim(), color: "text-red-500" };
  };

  return (
    <div className="relative w-full max-w-2xl mx-auto z-50" ref={searchContainerRef}>
      <div className="flex items-end gap-2">
        <div className="flex-1">
          <CyberInput
            label="Database Query"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onFocus={() => { if (results.length > 0 || error) setShowResults(true); }}
            placeholder="Input title sequence..."
          />
        </div>

        <button
          onClick={handleAiRecommend}
          className="h-[50px] px-4 bg-accent/10 border border-accent/40 text-accent hover:bg-accent hover:text-black transition-all duration-300 mb-[1px] group relative overflow-hidden"
          title="Neural Recommendations"
          style={{ clipPath: 'polygon(10px 0, 100% 0, 100% calc(100% - 10px), calc(100% - 10px) 100%, 0 100%, 0 10px)' }}
        >
          <div className="absolute inset-0 bg-accent/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300" />
          <div className="relative z-10">
            {aiLoading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Sparkles className="w-5 h-5" />}
          </div>
        </button>
      </div>

      {showResults && (results.length > 0 || error || loading) && (
        <div className="absolute top-full left-0 right-0 mt-2 bg-black/95 backdrop-blur-2xl border border-white/20 overflow-hidden max-h-[500px] flex flex-col z-50 animate-fade-in shadow-[0_20px_50px_rgba(0,0,0,0.8)]"
             style={{ clipPath: 'polygon(0 0, 100% 0, 100% calc(100% - 15px), calc(100% - 15px) 100%, 0 100%)' }}
        >
          {loading ? (
            <div className="p-10 flex flex-col items-center gap-2 text-accent">
              <Loader2 className="w-6 h-6 animate-spin" />
              <span className="font-mono text-[10px] uppercase tracking-widest">Querying Matrix...</span>
            </div>
          ) : error ? (
            (() => {
              const { icon: Icon, text, color } = getErrorConfig(error);
              return (
                <div className={`p-6 flex flex-col items-center justify-center ${color} gap-3 text-center border-l-2 border-red-500`}>
                  <Icon className="w-8 h-8 opacity-80" />
                  <span className="font-mono text-sm uppercase">{text}</span>
                </div>
              );
            })()
          ) : (
            <>
              {/* Refined Genre Filter Bar */}
              {results.length > 0 && (
                <div className="p-3 border-b border-white/10 bg-white/5 flex flex-col gap-2">
                  <div className="flex items-center justify-between text-[10px] font-mono uppercase tracking-widest text-gray-500 mb-1">
                    <div className="flex items-center gap-2">
                      <Filter className="w-3 h-3 text-accent" />
                      <span>Neural Filters</span>
                    </div>
                    <span className="opacity-40">{filteredResults.length} Results Found</span>
                  </div>
                  <div className="flex gap-2 pb-1 overflow-x-auto no-scrollbar mask-fade-right">
                    {genreData.map(genre => (
                      <button
                        key={genre.name}
                        onClick={() => setSelectedGenre(genre.name)}
                        className={`whitespace-nowrap px-3 py-1 text-[10px] font-mono uppercase transition-all flex items-center gap-2 border ${
                          selectedGenre === genre.name 
                            ? 'bg-accent/20 text-accent border-accent/50 shadow-[0_0_10px_var(--accent-dim)]' 
                            : 'text-gray-500 hover:text-gray-300 border-transparent hover:bg-white/5'
                        }`}
                        style={{ clipPath: 'polygon(5px 0, 100% 0, 100% calc(100% - 5px), calc(100% - 5px) 100%, 0 100%, 0 5px)' }}
                      >
                        {genre.name}
                        <span className={`text-[8px] opacity-40 ${selectedGenre === genre.name ? 'opacity-100' : ''}`}>[{genre.count}]</span>
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {/* Filtered Results List */}
              <div className="overflow-y-auto custom-scrollbar flex-1 max-h-96">
                {filteredResults.length === 0 ? (
                  <div className="p-10 text-center text-gray-600 font-mono text-xs uppercase tracking-widest flex flex-col items-center gap-3">
                    <Database className="w-8 h-8 opacity-10" />
                    <span>No results found in {selectedGenre} archive</span>
                  </div>
                ) : (
                  filteredResults.map((anime) => {
                    const isInLibrary = watchlist.some(w => w.animeId === anime.mal_id);
                    return (
                      <div 
                        key={anime.mal_id} 
                        className={`flex items-center p-3 cursor-pointer group border-b border-white/5 last:border-0 transition-all ${isInLibrary ? 'opacity-60 bg-white/5 cursor-default' : 'hover:bg-accent/10'}`}
                        onClick={() => handleInitiateAdd(anime)}
                      >
                        <div className="relative shrink-0">
                          <img 
                            src={anime.images.jpg.image_url} 
                            alt={anime.title} 
                            className={`w-12 h-16 object-cover border border-white/20 transition-all ${isInLibrary ? 'grayscale' : 'group-hover:border-accent group-hover:scale-105'}`}
                          />
                          {isInLibrary && (
                            <div className="absolute inset-0 flex items-center justify-center bg-black/60">
                              <BookmarkCheck className="w-6 h-6 text-accent" />
                            </div>
                          )}
                        </div>
                        <div className="ml-4 flex-1 min-w-0">
                          <h4 className={`font-mono font-bold uppercase tracking-tight truncate transition-colors ${isInLibrary ? 'text-gray-500' : 'text-gray-200 group-hover:text-accent'}`}>
                            {anime.title}
                          </h4>
                          <div className="text-[10px] font-mono text-gray-500 flex items-center gap-2 mt-1">
                            <span className="text-accent/70">{anime.episodes ? `${anime.episodes} EPS` : 'ONGOING'}</span>
                            <span className="opacity-20">|</span>
                            <span className="truncate">{anime.genres.slice(0, 2).map(g => g.name).join(', ')}</span>
                          </div>
                        </div>
                        {isInLibrary ? (
                          <div className="shrink-0 flex items-center gap-1 text-[8px] font-mono text-accent/50 uppercase tracking-tighter border border-accent/20 px-2 py-1">
                            LINK_ACTIVE
                          </div>
                        ) : (
                          <button 
                            onClick={(e) => { e.stopPropagation(); handleInitiateAdd(anime); }}
                            className="ml-3 p-2 border border-accent/30 text-accent group-hover:bg-accent group-hover:text-black group-hover:border-accent transition-all duration-300"
                          >
                            <Plus className="w-4 h-4" />
                          </button>
                        )}
                      </div>
                    );
                  })
                )}
              </div>
            </>
          )}
        </div>
      )}

      {/* Add Dialog Modal */}
      {selectedAnime && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-fade-in">
          <CyberCard className="w-full max-w-sm">
            <div className="relative h-32 bg-gray-900 border-b border-white/10 mb-4 overflow-hidden">
               <div className="absolute inset-0 bg-cover bg-center opacity-40 grayscale" style={{ backgroundImage: `url(${selectedAnime.images.jpg.large_image_url})` }} />
               <div className="absolute inset-0 bg-gradient-to-t from-black to-transparent" />
               <div className="absolute bottom-2 left-4 pr-10">
                  <h3 className="text-lg font-black font-mono text-white uppercase line-clamp-1 drop-shadow-md">{selectedAnime.title}</h3>
               </div>
               <button onClick={() => setSelectedAnime(null)} className="absolute top-2 right-2 p-2 bg-black/60 rounded-full text-gray-500 hover:text-red-500 transition-colors"><X className="w-5 h-5" /></button>
            </div>

            <form onSubmit={handleConfirmAdd} className="p-4 pt-0 space-y-4">
              <div className="flex items-center gap-2 text-accent mb-1">
                <ChevronRight className="w-4 h-4" />
                <p className="text-xs font-mono tracking-widest uppercase">Sync New Record</p>
              </div>
              <div>
                <label className="block text-[10px] font-mono text-gray-500 mb-2 uppercase">Initial Progress (Episodes)</label>
                <div className="flex items-center gap-3">
                  <input 
                    type="number" 
                    min="0"
                    max={selectedAnime.episodes || 9999}
                    value={watchedInput}
                    onChange={(e) => setWatchedInput(e.target.value)}
                    className="flex-1 bg-black border border-gray-700 text-accent px-4 py-2 font-mono text-xl focus:border-accent outline-none transition-colors"
                    autoFocus
                  />
                  <div className="text-sm font-mono text-gray-600">/ {selectedAnime.episodes || '???'}</div>
                </div>
              </div>
              <div className="flex gap-3 mt-6">
                <CyberButton onClick={() => setSelectedAnime(null)} className="flex-1 text-[10px]">Abort</CyberButton>
                <CyberButton type="submit" primary className="flex-1 text-[10px]">Confirm_Link</CyberButton>
              </div>
            </form>
          </CyberCard>
        </div>
      )}

      {/* AI Recommendations Modal */}
      {showAiModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md animate-fade-in">
          <CyberCard className="w-full max-w-lg border-accent/50">
             <div className="bg-accent/10 p-4 border-b border-accent/30 flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <Database className="w-5 h-5 text-accent animate-pulse" />
                  <GlitchText className="font-mono font-bold text-accent tracking-widest">NEURAL_ANALYSIS</GlitchText>
                </div>
                <button onClick={() => setShowAiModal(false)} className="text-accent hover:text-white transition-colors p-1"><X className="w-6 h-6" /></button>
             </div>

             <div className="p-6 max-h-[60vh] overflow-y-auto custom-scrollbar">
                {aiLoading ? (
                  <div className="flex flex-col items-center justify-center py-12 space-y-4">
                    <Loader2 className="w-12 h-12 text-accent animate-spin" />
                    <p className="font-mono text-[10px] text-accent animate-pulse tracking-[0.3em]">EXTRACTING DATA FROM MATRIX...</p>
                  </div>
                ) : (
                  <div className="font-mono text-sm leading-relaxed text-gray-300">
                    <div className="mb-6 p-3 bg-accent/5 border-l-4 border-accent text-[10px] text-gray-400">
                      STATUS: {watchlist.length} ACTIVE_SOURCES DETECTED.<br/>
                      ENCRYPTION_LAYER: ALPHA_9<br/>
                      SYNC_DATE: {new Date().toLocaleDateString()}
                    </div>
                    <div className="space-y-6">
                      {aiRecommendations.split('\n').filter(l => l.trim()).map((line, i) => (
                        <div key={i} className="group flex gap-4 transition-all">
                          <div className="text-accent mt-1 font-bold opacity-30 group-hover:opacity-100">0{i+1}</div>
                          <p className="group-hover:text-accent transition-colors leading-relaxed">{line}</p>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
             </div>
          </CyberCard>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import firebase from 'firebase/compat/app';
import { auth, db, googleProvider } from './firebase';
import { Anime, WatchListEntry, WatchHistoryItem, ThemeSettings } from './types';
import { calculateStats } from './services/statsService';
import { AnimeSearch } from './components/AnimeSearch';
import { AnimeCard } from './components/AnimeCard';
import { StatsBoard } from './components/StatsBoard';
import { UserProfile } from './components/UserProfile';
import { HistoryModal } from './components/HistoryModal';
import { HomePage } from './components/HomePage';
import { CyberBackground, CyberButton, CyberInput, CyberCard, GlitchText } from './components/CyberUI';
import { Logo } from './components/Logo';
import { AmbientSound } from './components/AmbientSound';
import { Loader2, LogOut, History, ArrowLeft, Ghost, Wifi, AlertTriangle, X, CloudOff, Cloud, RefreshCw, UserCheck, Zap, Palette, CloudUpload } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<firebase.User | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [watchlist, setWatchlist] = useState<WatchListEntry[]>([]);
  const [history, setHistory] = useState<WatchHistoryItem[]>([]);
  const [sortType, setSortType] = useState<'updated' | 'title'>('updated');
  const [showProfile, setShowProfile] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [isOffline, setIsOffline] = useState(!navigator.onLine);
  const [hasPendingWrites, setHasPendingWrites] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSyncTime, setLastSyncTime] = useState<Date | null>(null);
  const [themeSettings, setThemeSettings] = useState<ThemeSettings | null>(null);
  const [pendingOpsCount, setPendingOpsCount] = useState(0);

  // Auth Form State
  const [showAuth, setShowAuth] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isSignUp, setIsSignUp] = useState(false);
  const [error, setError] = useState('');
  const [formLoading, setFormLoading] = useState(false);

  // Debounce and Sync Refs
  const syncQueue = useRef<Record<string, { timer: NodeJS.Timeout, delta: number, initialWatched: number }>>({});

  // Apply theme to document
  useEffect(() => {
    const root = document.documentElement;
    if (themeSettings) {
      root.style.setProperty('--accent-color', themeSettings.accentColor);
      try {
        const hex = themeSettings.accentColor.replace('#', '');
        const r = parseInt(hex.substring(0, 2), 16);
        const g = parseInt(hex.substring(2, 4), 16);
        const b = parseInt(hex.substring(4, 6), 16);
        root.style.setProperty('--accent-dim', `rgba(${r}, ${g}, ${b}, 0.2)`);
      } catch (e) {
        root.style.setProperty('--accent-dim', `rgba(0, 255, 159, 0.2)`);
      }

      if (themeSettings.mode === 'light') {
        root.classList.add('light');
        root.classList.remove('dark');
      } else {
        root.classList.add('dark');
        root.classList.remove('light');
      }
    } else {
      root.classList.add('dark');
      root.classList.remove('light');
      root.style.setProperty('--accent-color', '#00ff9f');
      root.style.setProperty('--accent-dim', 'rgba(0, 255, 159, 0.2)');
    }
  }, [themeSettings]);

  // Network Listener
  useEffect(() => {
    const handleOnline = () => setIsOffline(false);
    const handleOffline = () => setIsOffline(true);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Auth Listener
  useEffect(() => {
    const unsubscribe = auth.onAuthStateChanged((currentUser) => {
      setUser(currentUser);
      setAuthLoading(false);
      if (currentUser) {
        setShowAuth(false);
      }
    });
    return () => unsubscribe();
  }, []);

  // Theme Listener
  useEffect(() => {
    if (!user) return;
    const unsub = db.collection('users').doc(user.uid).onSnapshot((doc) => {
      if (doc.exists) {
        const data = doc.data();
        if (data?.theme) {
          setThemeSettings(data.theme);
        }
      }
    });
    return () => unsub();
  }, [user]);

  const formatFirestoreDate = (val: any): string => {
    if (!val) return new Date().toISOString();
    if (typeof val.toDate === 'function') return val.toDate().toISOString();
    return val;
  };

  const syncData = async () => {
    if (!user) return;
    setIsSyncing(true);
    setError('');

    try {
      const watchlistRef = db.collection('users').doc(user.uid).collection('watchlist');
      const historyRef = db.collection('users').doc(user.uid).collection('history');

      const [wSnap, hSnap] = await Promise.all([
        watchlistRef.get({ source: 'server' }),
        historyRef.get({ source: 'server' })
      ]);

      const wList = wSnap.docs.map(doc => ({ 
        id: doc.id, 
        ...doc.data(),
        updatedAt: formatFirestoreDate(doc.get('updatedAt'))
      })) as WatchListEntry[];

      const hList = hSnap.docs.map(doc => ({ 
        id: doc.id, 
        ...doc.data(),
        timestamp: formatFirestoreDate(doc.get('timestamp'))
      })) as WatchHistoryItem[];

      setWatchlist(wList);
      setHistory(hList);
      setLastSyncTime(new Date());
    } catch (err: any) {
      setError("SYNC_LINK_TIMEOUT: Retrying with local cache.");
    } finally {
      setIsSyncing(false);
    }
  };

  useEffect(() => {
    if (!user) {
      setWatchlist([]);
      setHistory([]);
      return;
    }

    const userRef = db.collection('users').doc(user.uid);

    const unsubWatchlist = userRef.collection('watchlist').onSnapshot({ includeMetadataChanges: true }, (snapshot) => {
      const list = snapshot.docs.map(doc => {
        const data = doc.data();
        return {
          id: doc.id,
          ...data,
          updatedAt: formatFirestoreDate(data.updatedAt),
          pending: doc.metadata.hasPendingWrites
        };
      }) as WatchListEntry[];

      setWatchlist(list);
      setHasPendingWrites(snapshot.metadata.hasPendingWrites);
      if (!snapshot.metadata.hasPendingWrites) {
        setLastSyncTime(new Date());
      }
    });

    const unsubHistory = userRef.collection('history').onSnapshot((snapshot) => {
      const hist = snapshot.docs.map(doc => {
        const data = doc.data();
        return {
          id: doc.id,
          ...data,
          timestamp: formatFirestoreDate(data.timestamp)
        };
      }) as WatchHistoryItem[];
      setHistory(hist);
    });

    const unsubSync = db.onSnapshotsInSync(() => {
      setHasPendingWrites(false);
    });

    return () => {
      unsubWatchlist();
      unsubHistory();
      unsubSync();
    };
  }, [user]);

  const sortedWatchlist = useMemo(() => {
    const data = [...watchlist];
    if (sortType === 'updated') {
      return data.sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime());
    } else {
      return data.sort((a, b) => a.title.localeCompare(b.title));
    }
  }, [watchlist, sortType]);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setFormLoading(true);
    try {
      if (isSignUp) {
        await auth.createUserWithEmailAndPassword(email, password);
      } else {
        await auth.signInWithEmailAndPassword(email, password);
      }
    } catch (err: any) {
      setError(err.message.replace('Firebase: ', ''));
    } finally {
      setFormLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
    setError('');
    setFormLoading(true);
    try {
      await auth.signInWithPopup(googleProvider);
    } catch (err: any) {
      setError(err.message.replace('Firebase: ', ''));
      setFormLoading(false);
    }
  };

  const handleLogout = () => {
      setError('');
      auth.signOut();
  };

  const addAnimeToLibrary = async (anime: Anime, initialWatched: number) => {
    if (!user) return;

    // Optimistic UI for Adding
    const tempId = `temp-${Date.now()}`;
    const tempEntry: WatchListEntry = {
      id: tempId,
      animeId: anime.mal_id,
      title: anime.title,
      imageUrl: anime.images.jpg.large_image_url,
      totalEpisodes: anime.episodes,
      watchedEpisodes: initialWatched,
      genres: anime.genres.map(g => g.name),
      score: anime.score || null,
      synopsis: anime.synopsis || "",
      updatedAt: new Date().toISOString(),
      pending: true
    };

    setWatchlist(prev => [tempEntry, ...prev]);

    try {
        const batch = db.batch();
        const watchlistRef = db.collection('users').doc(user.uid).collection('watchlist').doc();

        batch.set(watchlistRef, {
          animeId: anime.mal_id,
          title: anime.title,
          imageUrl: anime.images.jpg.large_image_url,
          totalEpisodes: anime.episodes,
          watchedEpisodes: initialWatched,
          genres: anime.genres.map(g => g.name),
          score: anime.score || null,
          synopsis: anime.synopsis || "",
          updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });

        if (initialWatched > 0) {
            const historyRef = db.collection('users').doc(user.uid).collection('history').doc();
            batch.set(historyRef, {
                animeId: anime.mal_id,
                animeTitle: anime.title,
                episodesDelta: initialWatched,
                timestamp: firebase.firestore.FieldValue.serverTimestamp()
            });
        }

        await batch.commit();
    } catch (err: any) {
        setError(`WRITE_ERROR: ${err.message}`);
        // Revert optimistic add
        setWatchlist(prev => prev.filter(e => e.id !== tempId));
    }
  };

  const performSyncUpdate = async (entry: WatchListEntry, finalAmount: number, delta: number) => {
    if (!user) return;
    setPendingOpsCount(prev => Math.max(0, prev - 1));

    try {
        const batch = db.batch();
        const entryRef = db.collection('users').doc(user.uid).collection('watchlist').doc(entry.id);
        const historyRef = db.collection('users').doc(user.uid).collection('history').doc();

        batch.update(entryRef, {
          watchedEpisodes: finalAmount,
          updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });

        batch.set(historyRef, {
          animeId: entry.animeId,
          animeTitle: entry.title,
          episodesDelta: delta,
          timestamp: firebase.firestore.FieldValue.serverTimestamp()
        });

        await batch.commit();
    } catch (err: any) {
        setError(`DEBOUNCED_SYNC_ERROR: ${err.message}`);
    }
  };

  const updateEpisodesOptimistic = (entry: WatchListEntry, newAmount: number) => {
    if (!user) return;

    // 1. Update Application State Immediately (Optimistic)
    setWatchlist(prev => prev.map(e => e.id === entry.id ? { ...e, watchedEpisodes: newAmount, pending: true } : e));

    // 2. Debounce Cloud Sync
    if (syncQueue.current[entry.id]) {
      clearTimeout(syncQueue.current[entry.id].timer);
      const prevDelta = syncQueue.current[entry.id].delta;
      const initialWatched = syncQueue.current[entry.id].initialWatched;

      syncQueue.current[entry.id] = {
        initialWatched,
        delta: newAmount - initialWatched,
        timer: setTimeout(() => {
          const { delta } = syncQueue.current[entry.id];
          performSyncUpdate(entry, newAmount, delta);
          delete syncQueue.current[entry.id];
        }, 2000)
      };
    } else {
      setPendingOpsCount(prev => prev + 1);
      syncQueue.current[entry.id] = {
        initialWatched: entry.watchedEpisodes,
        delta: newAmount - entry.watchedEpisodes,
        timer: setTimeout(() => {
          const { delta } = syncQueue.current[entry.id];
          performSyncUpdate(entry, newAmount, delta);
          delete syncQueue.current[entry.id];
        }, 2000)
      };
    }
  };

  if (authLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-black text-accent">
        <div className="flex flex-col items-center gap-4">
            <Loader2 className="w-12 h-12 animate-spin text-accent" />
            <div className="font-mono text-sm animate-pulse uppercase tracking-[0.2em] text-accent">Matrix_Link_Establishing...</div>
        </div>
      </div>
    );
  }

  if (!user) {
    if (!showAuth) return <><HomePage onStart={() => setShowAuth(true)} isDark={true} toggleTheme={() => {}} /><AmbientSound /></>;
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-4 relative overflow-hidden bg-black text-white">
        <CyberBackground />
        <AmbientSound />
        <button onClick={() => setShowAuth(false)} className="absolute top-6 left-6 z-50 text-gray-500 hover:text-accent flex items-center gap-2 font-mono text-xs transition-colors">
          <ArrowLeft className="w-4 h-4" /> <span>ABORT_SEQUENCE</span>
        </button>
        <CyberCard className="w-full max-w-md animate-slide-up">
          <div className="p-8">
            <div className="text-center mb-10">
              <div className="flex justify-center mb-6 relative">
                 <div className="absolute inset-0 bg-accent/20 blur-2xl rounded-full" />
                 <Logo className="w-24 h-24 relative z-10 drop-shadow-[0_0_10px_var(--accent-dim)] animate-pulse" />
              </div>
              <h1 className="text-3xl font-black text-white tracking-tighter mb-1"><GlitchText>ACCESS_CONTROL</GlitchText></h1>
              <p className="text-accent font-mono text-[10px] tracking-[0.2em] uppercase">Verify Identity to Proceed</p>
            </div>
            <form onSubmit={handleAuth} className="space-y-6">
              <CyberInput label="User ID / Email" type="email" required value={email} onChange={(e) => setEmail(e.target.value)} placeholder="runner@net.city" />
              <CyberInput label="Access Key / Password" type="password" required value={password} onChange={(e) => setPassword(e.target.value)} placeholder="••••••••" />
              {error && <div className="p-3 border border-cyber-pink bg-cyber-pink/10 text-cyber-pink text-xs font-mono flex items-center gap-2"><Wifi className="w-4 h-4"/> ERROR: {error}</div>}
              <CyberButton type="submit" primary className="w-full" disabled={formLoading}>
                {formLoading ? <div className="flex items-center justify-center gap-2"><Loader2 className="w-5 h-5 animate-spin" /><span>PROCESSING...</span></div> : (isSignUp ? 'Initialize_Account' : 'Jack_In')}
              </CyberButton>
            </form>
            <div className="mt-8 relative"><div className="absolute inset-0 flex items-center"><div className="w-full border-t border-gray-800"></div></div><div className="relative flex justify-center text-xs"><span className="bg-black px-2 text-gray-600 font-mono">ALTERNATE_UPLINK</span></div></div>
            <button type="button" onClick={handleGoogleLogin} disabled={formLoading} className="mt-6 w-full py-3 bg-white hover:bg-gray-100 text-black font-sans font-bold text-sm transition-all flex items-center justify-center gap-3 uppercase tracking-wider group shadow-[0_0_15px_rgba(255,255,255,0.1)] hover:shadow-[0_0_20px_rgba(255,255,255,0.3)]">
              <svg className="w-5 h-5" viewBox="0 0 24 24">
                <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4" />
                <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853" />
                <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05" />
                <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335" />
              </svg>
              <span>Sign In with Google</span>
            </button>
            <div className="mt-8 text-center">
              <button onClick={() => setIsSignUp(!isSignUp)} className="text-xs text-accent hover:text-white font-mono hover:underline decoration-accent underline-offset-4">
                {isSignUp ? "HAS_ACCOUNT? EXECUTE LOGIN" : "NO_DATA? CREATE NEW RECORD"}
              </button>
            </div>
          </div>
        </CyberCard>
      </div>
    );
  }

  const stats = calculateStats(history, watchlist);

  return (
    <div className="min-h-screen relative pb-20 font-sans selection:bg-cyber-pink selection:text-white bg-[var(--bg-color)] text-[var(--text-color)] transition-colors duration-500">
      <CyberBackground />
      <AmbientSound />

      <header className="sticky top-0 z-40 bg-[var(--bg-color)]/80 backdrop-blur-md border-b border-[var(--border-color)]">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-3 group">
            <Logo className="w-10 h-10 hover:scale-110 transition-transform duration-300" />
            <span className="font-mono font-bold text-xl tracking-tighter text-[var(--text-color)] group-hover:text-accent transition-colors">ANI<span className="text-accent">TRACK</span></span>

            <button onClick={syncData} className="ml-4 flex items-center gap-2 border-l border-gray-800 pl-4 h-8 group/sync">
               {hasPendingWrites || isSyncing || pendingOpsCount > 0 ? (
                 <div className="flex items-center gap-2 text-amber-500 animate-pulse">
                    <CloudUpload className="w-3.5 h-3.5 animate-bounce" />
                    <span className="text-[10px] font-mono font-bold hidden md:inline">
                      {pendingOpsCount > 0 ? `${pendingOpsCount} PENDING_OPS` : 'UPLINKING...'}
                    </span>
                 </div>
               ) : (
                 <div className="flex items-center gap-2 text-accent">
                    <Cloud className="w-4 h-4 group-hover/sync:scale-110 transition-transform" />
                    <span className="text-[10px] font-mono font-bold hidden md:inline">SYNCHRONIZED</span>
                 </div>
               )}
            </button>
          </div>

          <div className="flex items-center gap-6">
            <div className="hidden lg:flex flex-col items-end cursor-default font-mono border-r border-gray-800 pr-6 mr-2">
                <span className="text-xs font-bold text-accent leading-none mb-1 flex items-center gap-2">
                   <UserCheck className="w-3 h-3 text-accent" /> {user.displayName || 'ANON_RUNNER'}
                </span>
                <span className="text-[9px] text-gray-500 uppercase tracking-widest">{lastSyncTime ? `SYNC_OK: ${lastSyncTime.toLocaleTimeString()}` : 'INITIALIZING...'}</span>
            </div>
            <div className="flex items-center gap-4">
                <button onClick={() => setShowProfile(true)} className="w-10 h-10 border border-gray-700 hover:border-accent transition-all flex items-center justify-center overflow-hidden bg-black relative">
                     {user.photoURL ? <img src={user.photoURL} alt="User" className="w-full h-full object-cover opacity-80" /> : <Ghost className="w-5 h-5 text-gray-500" />}
                     <div className="absolute top-0 right-0 w-2 h-2 bg-accent border border-black rounded-full" />
                </button>
                <button onClick={handleLogout} className="p-2 text-gray-600 hover:text-red-500 transition-colors"><LogOut className="w-5 h-5" /></button>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 pt-10 relative z-10">
        {(error || isOffline) && (
          <div className={`mb-8 p-4 border flex items-center justify-between gap-4 animate-fade-in ${isOffline ? 'bg-amber-900/20 border-amber-500 text-amber-500' : 'bg-cyber-pink/10 border-cyber-pink text-cyber-pink'}`}>
            <div className="flex items-center gap-3">
               {isOffline ? <CloudOff className="w-6 h-6" /> : <AlertTriangle className="w-6 h-6" />}
               <div><h3 className="font-bold font-mono tracking-wider">{isOffline ? 'OFFLINE_MODE' : 'SYNC_PROTOCOL_ERROR'}</h3><p className="text-xs font-mono opacity-80">{isOffline ? 'LOCAL_CACHE_ONLY. RECONNECT TO UPLOAD.' : error}</p></div>
            </div>
            <button onClick={() => setError('')} className="p-2 hover:bg-white/10 rounded"><X className="w-5 h-5" /></button>
          </div>
        )}

        <section className="mb-16 animate-fade-in">
          <div className="flex items-end justify-between mb-8 border-b border-[var(--border-color)] pb-4">
             <div><h2 className="text-2xl font-black text-[var(--text-color)] uppercase tracking-tight mb-1">Data Overview</h2><div className="text-[10px] font-mono text-gray-500">NEURAL_DASHBOARD</div></div>
             <button onClick={() => setShowHistory(true)} className="flex items-center gap-2 px-4 py-2 bg-white/5 border border-[var(--border-color)] hover:border-accent text-gray-400 text-xs font-mono transition-all uppercase tracking-wider">
               <History className="w-3 h-3" /> View Logs
             </button>
          </div>
          <StatsBoard stats={stats} />
        </section>

        <section className="mb-20 flex flex-col items-center">
          <div className="w-full max-w-2xl text-center mb-8">
             <h2 className="text-xl font-bold text-[var(--text-color)] uppercase tracking-widest mb-2"><GlitchText>Database Entry</GlitchText></h2>
             <div className="h-0.5 w-24 bg-accent mx-auto" />
          </div>
          <AnimeSearch onAddAnime={addAnimeToLibrary} watchlist={watchlist} />
        </section>

        <section>
          <div className="flex flex-col sm:flex-row items-end justify-between mb-8 gap-4 border-b border-[var(--border-color)] pb-4">
            <div className="flex items-center gap-4">
                <h2 className="text-3xl font-black text-[var(--text-color)] flex items-center gap-3 uppercase">MEMORY BANK <span className="text-lg font-mono font-normal text-accent border border-accent px-2 py-0.5">{watchlist.length}</span></h2>
                <button onClick={syncData} disabled={isSyncing} className={`p-2 border border-gray-800 text-gray-600 hover:text-accent hover:border-accent transition-all rounded-full ${isSyncing ? 'animate-spin' : ''}`}><RefreshCw className="w-4 h-4" /></button>
            </div>
            <div className="flex items-center gap-3">
              <span className="text-[10px] font-mono text-gray-500 uppercase">Sort:</span>
              <div className="flex gap-1">
                <button onClick={() => setSortType('updated')} className={`px-3 py-1 text-[10px] font-mono border ${sortType === 'updated' ? 'bg-accent/20 border-accent text-accent' : 'border-gray-800 text-gray-500 hover:border-gray-600'}`}>Recent</button>
                <button onClick={() => setSortType('title')} className={`px-3 py-1 text-[10px] font-mono border ${sortType === 'title' ? 'bg-accent/20 border-accent text-accent' : 'border-gray-800 text-gray-500 hover:border-gray-600'}`}>Alpha</button>
              </div>
            </div>
          </div>

          {watchlist.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-24 border border-dashed border-gray-800 bg-white/5">
              <Ghost className="w-16 h-16 text-gray-800 mb-4" />
              <p className="font-mono text-gray-500 text-lg uppercase">Memory Void</p>
              <p className="font-mono text-gray-700 text-[10px] mt-2 tracking-widest uppercase">Search to populate</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 sm:gap-6 lg:gap-8">
              {sortedWatchlist.map((entry) => (
                <AnimeCard 
                  key={entry.id} 
                  entry={entry} 
                  onUpdateEpisodes={updateEpisodesOptimistic} 
                  onRemove={(id) => {
                    if (window.confirm("WARNING: Purge record?")) {
                      db.collection('users').doc(user.uid).collection('watchlist').doc(id).delete();
                    }
                  }} 
                />
              ))}
            </div>
          )}
        </section>
      </main>

      {showProfile && user && <UserProfile user={user} stats={stats} animeCount={watchlist.length} themeSettings={themeSettings} onClose={() => setShowProfile(false)} />}
      {showHistory && <HistoryModal history={history} watchlist={watchlist} onClose={() => setShowHistory(false)} onUpdate={async (id, data) => {
        await db.collection('users').doc(user.uid).collection('history').doc(id).update(data);
      }} onDelete={async (id) => {
        await db.collection('users').doc(user.uid).collection('history').doc(id).delete();
      }} />}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Plus, Minus, Trash2, Activity, RefreshCw, Star, ChevronDown, ChevronUp, Database, CloudUpload } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { WatchListEntry } from '../types';
import { GENRE_COLORS } from '../constants';

interface AnimeCardProps {
  entry: WatchListEntry;
  onUpdateEpisodes: (entry: WatchListEntry, newAmount: number) => void;
  onRemove: (id: string) => void;
}

export const AnimeCard: React.FC<AnimeCardProps> = ({ entry, onUpdateEpisodes, onRemove }) => {
  const [isUpdating, setIsUpdating] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);

  // Local optimistic state for instant feedback
  const [optimisticWatched, setOptimisticWatched] = useState(entry.watchedEpisodes);

  // Sync optimistic state with source of truth when it settles
  useEffect(() => {
    setOptimisticWatched(entry.watchedEpisodes);
    setIsUpdating(true);
    const timer = setTimeout(() => setIsUpdating(false), 800);
    return () => clearTimeout(timer);
  }, [entry.watchedEpisodes]);

  const handleUpdate = (e: React.MouseEvent, delta: number) => {
    e.stopPropagation();
    const newAmount = optimisticWatched + delta;
    if (newAmount < 0) return;
    if (entry.totalEpisodes && newAmount > entry.totalEpisodes) return;

    setOptimisticWatched(newAmount);
    onUpdateEpisodes(entry, newAmount);
  };

  const handleRemove = (e: React.MouseEvent) => {
    e.stopPropagation();
    onRemove(entry.id);
  };

  const progress = entry.totalEpisodes 
    ? (optimisticWatched / entry.totalEpisodes) * 100 
    : 0;

  return (
    <div 
        onClick={() => setIsExpanded(!isExpanded)}
        className={`group relative bg-[var(--card-bg)] border transition-all duration-500 flex flex-col h-fit cursor-pointer animate-slide-up overflow-hidden ${
          entry.pending ? 'border-amber-500/50 shadow-[0_0_15px_rgba(245,158,11,0.1)]' : 'border-white/10 hover:border-accent'
        } ${isExpanded ? 'ring-1 ring-accent/30 shadow-[0_0_20px_var(--accent-dim)]' : ''}`}
        style={{ clipPath: 'polygon(15px 0, 100% 0, 100% calc(100% - 15px), calc(100% - 15px) 100%, 0 100%, 0 15px)' }}
    >
      <div className="relative aspect-[16/9] overflow-hidden border-b border-white/10">
        <img 
          src={entry.imageUrl} 
          alt={entry.title} 
          className={`w-full h-full object-cover transition-all duration-500 group-hover:scale-105 ${entry.pending ? 'grayscale opacity-60' : 'grayscale group-hover:grayscale-0'} ${isExpanded ? 'grayscale-0 scale-105' : ''}`}
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black via-black/50 to-transparent" />

        <div className="absolute bottom-0 left-0 p-4 w-full">
            <h3 className={`font-mono font-bold text-lg leading-tight line-clamp-1 drop-shadow-[0_2px_4px_rgba(0,0,0,0.8)] transition-colors ${entry.pending ? 'text-amber-500' : 'text-white'}`}>
                {entry.title}
            </h3>
            <div className={`h-[2px] mt-2 transition-all duration-500 ${entry.pending ? 'w-1/2 bg-amber-500 animate-pulse' : isExpanded ? 'w-full bg-accent' : 'w-10 bg-accent group-hover:w-full'}`} />
        </div>

        {entry.score && (
          <div className="absolute top-2 left-2 flex items-center gap-1 px-2 py-0.5 bg-black/70 border border-accent/40 backdrop-blur-sm">
             <Star className="w-3 h-3 text-yellow-400 fill-yellow-400" />
             <span className="text-[10px] font-mono font-bold text-accent">{entry.score}</span>
          </div>
        )}

        <button onClick={handleRemove} className="absolute top-0 right-0 p-2 bg-black/60 text-gray-500 hover:text-red-500 hover:bg-black transition-colors backdrop-blur-sm z-10"><Trash2 className="w-4 h-4" /></button>

        {entry.pending && (
          <div className="absolute top-2 right-12 p-1.5 bg-amber-500/20 text-amber-500 backdrop-blur-sm flex items-center gap-1 font-mono text-[9px] border border-amber-500/50 z-10">
             <CloudUpload className="w-2.5 h-2.5 animate-bounce" />
             <span className="tracking-tighter">PENDING_SYNC</span>
          </div>
        )}
      </div>

      <div className="p-4 flex flex-col backdrop-blur-sm relative">
        <div className={`absolute inset-0 bg-accent/5 pointer-events-none transition-opacity duration-500 ${isUpdating && !entry.pending ? 'opacity-100' : 'opacity-0'}`} />

        <div className="flex flex-wrap gap-1 mb-4 relative z-10">
          {entry.genres.slice(0, 3).map((genre) => {
             const colorClass = GENRE_COLORS[genre] || GENRE_COLORS['Default'];
             return <span key={genre} className={`text-[9px] px-1.5 py-0.5 font-mono uppercase tracking-wider ${colorClass}`}>{genre}</span>;
          })}
        </div>

        <div className="relative z-10">
          <div className="flex justify-between items-end mb-2 font-mono text-xs">
            <span className={`transition-colors flex items-center gap-1 ${entry.pending ? 'text-amber-500/70' : 'text-gray-500 group-hover:text-accent'} ${isExpanded ? 'text-accent' : ''}`}>
               <Activity className="w-3 h-3" /> PROGRESS
            </span>
            <span className={entry.pending ? 'text-amber-500' : 'text-[var(--text-color)]'}>
              {optimisticWatched} <span className="text-gray-500">/ {entry.totalEpisodes || '?'}</span>
            </span>
          </div>

          <div className={`w-full bg-gray-900/40 h-1.5 mb-4 border overflow-hidden rounded-sm transition-colors ${entry.pending ? 'border-amber-900/50' : 'border-gray-800'}`}>
            <div 
              className={`h-full relative transition-all duration-300 ease-out ${
                entry.pending 
                  ? 'bg-amber-600 shadow-[0_0_10px_#d97706]' 
                  : isUpdating 
                    ? 'bg-accent shadow-[0_0_20px_var(--accent-color)] brightness-125' 
                    : 'bg-accent shadow-[0_0_5px_var(--accent-dim)]'
              }`}
              style={{ width: `${entry.totalEpisodes ? progress : 100}%` }}
            >
                {entry.pending && (
                   <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/40 to-transparent animate-[shimmer_1.5s_infinite]" 
                        style={{ backgroundSize: '200% 100%' }} />
                )}
            </div>
          </div>

          <div className="flex items-center justify-between gap-2">
            <button onClick={(e) => handleUpdate(e, -1)} disabled={optimisticWatched <= 0} className="p-1.5 border border-gray-800 text-gray-500 hover:border-cyber-pink hover:text-cyber-pink transition-all disabled:opacity-30">
              <Minus className="w-4 h-4" />
            </button>
            <div className="flex flex-col items-center">
              <span className={`text-[10px] font-mono transition-colors ${entry.pending ? 'text-amber-500/50' : 'text-gray-500'}`}>
                {optimisticWatched * 24}m
              </span>
            </div>
            <button onClick={(e) => handleUpdate(e, 1)} disabled={entry.totalEpisodes !== null && optimisticWatched >= entry.totalEpisodes} className="p-1.5 border border-gray-800 text-gray-500 hover:border-accent hover:text-accent transition-all disabled:opacity-30">
              <Plus className="w-4 h-4" />
            </button>
          </div>
        </div>

        <AnimatePresence>
          {isExpanded && (
            <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }} className="overflow-hidden mt-6 border-t border-white/10 pt-4">
               <div className="flex items-center gap-2 mb-2 text-accent">
                 <Database className="w-3.5 h-3.5" />
                 <span className="text-[10px] font-mono font-bold tracking-widest uppercase">Memory_Extract</span>
               </div>
               {entry.synopsis ? <p className="text-[11px] font-sans leading-relaxed text-gray-400 line-clamp-6 italic">{entry.synopsis}</p> : <p className="text-[10px] font-mono text-gray-600 uppercase italic">No synopsis linked.</p>}
               <div className="mt-4 flex justify-center">
                 <button className="text-[9px] font-mono text-gray-600 hover:text-accent transition-colors uppercase tracking-widest flex items-center gap-1">Click to Retract <ChevronUp className="w-3 h-3" /></button>
               </div>
            </motion.div>
          )}
        </AnimatePresence>
        {!isExpanded && <div className="mt-2 flex justify-center opacity-0 group-hover:opacity-40 transition-opacity"><ChevronDown className="w-4 h-4 text-gray-500" /></div>}
      </div>
      <style>{`
        @keyframes shimmer {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(100%); }
        }
      `}</style>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import firebase from 'firebase/compat/app';
import { auth, db, googleProvider } from './firebase';
import { Anime, WatchListEntry, WatchHistoryItem, ThemeSettings } from './types';
import { calculateStats } from './services/statsService';
import { AnimeSearch } from './components/AnimeSearch';
import { AnimeCard } from './components/AnimeCard';
import { StatsBoard } from './components/StatsBoard';
import { UserProfile } from './components/UserProfile';
import { HistoryModal } from './components/HistoryModal';
import { HomePage } from './components/HomePage';
import { CyberBackground, CyberButton, CyberInput, CyberCard, GlitchText } from './components/CyberUI';
import { Logo } from './components/Logo';
import { AmbientSound } from './components/AmbientSound';
import { Loader2, LogOut, History, ArrowLeft, Ghost, Wifi, AlertTriangle, X, CloudOff, Cloud, RefreshCw, UserCheck, Zap, Palette, CloudUpload } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<firebase.User | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [watchlist, setWatchlist] = useState<WatchListEntry[]>([]);
  const [history, setHistory] = useState<WatchHistoryItem[]>([]);
  const [sortType, setSortType] = useState<'updated' | 'title'>('updated');
  const [showProfile, setShowProfile] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [isOffline, setIsOffline] = useState(!navigator.onLine);
  const [hasPendingWrites, setHasPendingWrites] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSyncTime, setLastSyncTime] = useState<Date | null>(null);
  const [themeSettings, setThemeSettings] = useState<ThemeSettings | null>(null);
  const [pendingOpsCount, setPendingOpsCount] = useState(0);

  // Auth Form State
  const [showAuth, setShowAuth] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isSignUp, setIsSignUp] = useState(false);
  const [error, setError] = useState('');
  const [formLoading, setFormLoading] = useState(false);

  // Debounce and Sync Refs
  // Fix: Replaced NodeJS.Timeout with ReturnType<typeof setTimeout> to resolve 'Cannot find namespace NodeJS' error in browser environment.
  const syncQueue = useRef<Record<string, { timer: ReturnType<typeof setTimeout>, delta: number, initialWatched: number }>>({});

  // Apply theme to document
  useEffect(() => {
    const root = document.documentElement;
    if (themeSettings) {
      root.style.setProperty('--accent-color', themeSettings.accentColor);
      try {
        const hex = themeSettings.accentColor.replace('#', '');
        const r = parseInt(hex.substring(0, 2), 16);
        const g = parseInt(hex.substring(2, 4), 16);
        const b = parseInt(hex.substring(4, 6), 16);
        root.style.setProperty('--accent-dim', `rgba(${r}, ${g}, ${b}, 0.2)`);
      } catch (e) {
        root.style.setProperty('--accent-dim', `rgba(0, 255, 159, 0.2)`);
      }

      if (themeSettings.mode === 'light') {
        root.classList.add('light');
        root.classList.remove('dark');
      } else {
        root.classList.add('dark');
        root.classList.remove('light');
      }
    } else {
      root.classList.add('dark');
      root.classList.remove('light');
      root.style.setProperty('--accent-color', '#00ff9f');
      root.style.setProperty('--accent-dim', 'rgba(0, 255, 159, 0.2)');
    }
  }, [themeSettings]);

  // Network Listener
  useEffect(() => {
    const handleOnline = () => setIsOffline(false);
    const handleOffline = () => setIsOffline(true);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Auth Listener
  useEffect(() => {
    const unsubscribe = auth.onAuthStateChanged((currentUser) => {
      setUser(currentUser);
      setAuthLoading(false);
      if (currentUser) {
        setShowAuth(false);
      }
    });
    return () => unsubscribe();
  }, []);

  // Theme Listener
  useEffect(() => {
    if (!user) return;
    const unsub = db.collection('users').doc(user.uid).onSnapshot((doc) => {
      if (doc.exists) {
        const data = doc.data();
        if (data?.theme) {
          setThemeSettings(data.theme);
        }
      }
    });
    return () => unsub();
  }, [user]);

  const formatFirestoreDate = (val: any): string => {
    if (!val) return new Date().toISOString();
    if (typeof val.toDate === 'function') return val.toDate().toISOString();
    return val;
  };

  const syncData = async () => {
    if (!user) return;
    setIsSyncing(true);
    setError('');

    try {
      const watchlistRef = db.collection('users').doc(user.uid).collection('watchlist');
      const historyRef = db.collection('users').doc(user.uid).collection('history');

      const [wSnap, hSnap] = await Promise.all([
        watchlistRef.get({ source: 'server' }),
        historyRef.get({ source: 'server' })
      ]);

      const wList = wSnap.docs.map(doc => ({ 
        id: doc.id, 
        ...doc.data(),
        updatedAt: formatFirestoreDate(doc.get('updatedAt'))
      })) as WatchListEntry[];

      const hList = hSnap.docs.map(doc => ({ 
        id: doc.id, 
        ...doc.data(),
        timestamp: formatFirestoreDate(doc.get('timestamp'))
      })) as WatchHistoryItem[];

      setWatchlist(wList);
      setHistory(hList);
      setLastSyncTime(new Date());
    } catch (err: any) {
      setError("SYNC_LINK_TIMEOUT: Retrying with local cache.");
    } finally {
      setIsSyncing(false);
    }
  };

  useEffect(() => {
    if (!user) {
      setWatchlist([]);
      setHistory([]);
      return;
    }

    const userRef = db.collection('users').doc(user.uid);

    const unsubWatchlist = userRef.collection('watchlist').onSnapshot({ includeMetadataChanges: true }, (snapshot) => {
      const list = snapshot.docs.map(doc => {
        const data = doc.data();
        return {
          id: doc.id,
          ...data,
          updatedAt: formatFirestoreDate(data.updatedAt),
          pending: doc.metadata.hasPendingWrites
        };
      }) as WatchListEntry[];

      setWatchlist(list);
      setHasPendingWrites(snapshot.metadata.hasPendingWrites);
      if (!snapshot.metadata.hasPendingWrites) {
        setLastSyncTime(new Date());
      }
    });

    const unsubHistory = userRef.collection('history').onSnapshot((snapshot) => {
      const hist = snapshot.docs.map(doc => {
        const data = doc.data();
        return {
          id: doc.id,
          ...data,
          timestamp: formatFirestoreDate(data.timestamp)
        };
      }) as WatchHistoryItem[];
      setHistory(hist);
    });

    const unsubSync = db.onSnapshotsInSync(() => {
      setHasPendingWrites(false);
    });

    return () => {
      unsubWatchlist();
      unsubHistory();
      unsubSync();
    };
  }, [user]);

  const sortedWatchlist = useMemo(() => {
    const data = [...watchlist];
    if (sortType === 'updated') {
      return data.sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime());
    } else {
      return data.sort((a, b) => a.title.localeCompare(b.title));
    }
  }, [watchlist, sortType]);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setFormLoading(true);
    try {
      if (isSignUp) {
        await auth.createUserWithEmailAndPassword(email, password);
      } else {
        await auth.signInWithEmailAndPassword(email, password);
      }
    } catch (err: any) {
      setError(err.message.replace('Firebase: ', ''));
    } finally {
      setFormLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
    setError('');
    setFormLoading(true);
    try {
      await auth.signInWithPopup(googleProvider);
    } catch (err: any) {
      setError(err.message.replace('Firebase: ', ''));
      setFormLoading(false);
    }
  };

  const handleLogout = () => {
      setError('');
      auth.signOut();
  };

  const addAnimeToLibrary = async (anime: Anime, initialWatched: number) => {
    if (!user) return;

    // Optimistic UI for Adding
    const tempId = `temp-${Date.now()}`;
    const tempEntry: WatchListEntry = {
      id: tempId,
      animeId: anime.mal_id,
      title: anime.title,
      imageUrl: anime.images.jpg.large_image_url,
      totalEpisodes: anime.episodes,
      watchedEpisodes: initialWatched,
      genres: anime.genres.map(g => g.name),
      score: anime.score || null,
      synopsis: anime.synopsis || "",
      updatedAt: new Date().toISOString(),
      pending: true
    };

    setWatchlist(prev => [tempEntry, ...prev]);

    try {
        const batch = db.batch();
        const watchlistRef = db.collection('users').doc(user.uid).collection('watchlist').doc();

        batch.set(watchlistRef, {
          animeId: anime.mal_id,
          title: anime.title,
          imageUrl: anime.images.jpg.large_image_url,
          totalEpisodes: anime.episodes,
          watchedEpisodes: initialWatched,
          genres: anime.genres.map(g => g.name),
          score: anime.score || null,
          synopsis: anime.synopsis || "",
          updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });

        if (initialWatched > 0) {
            const historyRef = db.collection('users').doc(user.uid).collection('history').doc();
            batch.set(historyRef, {
                animeId: anime.mal_id,
                animeTitle: anime.title,
                episodesDelta: initialWatched,
                timestamp: firebase.firestore.FieldValue.serverTimestamp()
            });
        }

        await batch.commit();
    } catch (err: any) {
        setError(`WRITE_ERROR: ${err.message}`);
        // Revert optimistic add
        setWatchlist(prev => prev.filter(e => e.id !== tempId));
    }
  };

  const performSyncUpdate = async (entry: WatchListEntry, finalAmount: number, delta: number) => {
    if (!user) return;
    setPendingOpsCount(prev => Math.max(0, prev - 1));

    try {
        const batch = db.batch();
        const entryRef = db.collection('users').doc(user.uid).collection('watchlist').doc(entry.id);
        const historyRef = db.collection('users').doc(user.uid).collection('history').doc();

        batch.update(entryRef, {
          watchedEpisodes: finalAmount,
          updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });

        batch.set(historyRef, {
          animeId: entry.animeId,
          animeTitle: entry.title,
          episodesDelta: delta,
          timestamp: firebase.firestore.FieldValue.serverTimestamp()
        });

        await batch.commit();
    } catch (err: any) {
        setError(`DEBOUNCED_SYNC_ERROR: ${err.message}`);
    }
  };

  const updateEpisodesOptimistic = (entry: WatchListEntry, newAmount: number) => {
    if (!user) return;

    // 1. Update Application State Immediately (Optimistic)
    setWatchlist(prev => prev.map(e => e.id === entry.id ? { ...e, watchedEpisodes: newAmount, pending: true } : e));

    // 2. Debounce Cloud Sync
    if (syncQueue.current[entry.id]) {
      clearTimeout(syncQueue.current[entry.id].timer);
      const prevDelta = syncQueue.current[entry.id].delta;
      const initialWatched = syncQueue.current[entry.id].initialWatched;

      syncQueue.current[entry.id] = {
        initialWatched,
        delta: newAmount - initialWatched,
        timer: setTimeout(() => {
          const { delta } = syncQueue.current[entry.id];
          performSyncUpdate(entry, newAmount, delta);
          delete syncQueue.current[entry.id];
        }, 2000)
      };
    } else {
      setPendingOpsCount(prev => prev + 1);
      syncQueue.current[entry.id] = {
        initialWatched: entry.watchedEpisodes,
        delta: newAmount - entry.watchedEpisodes,
        timer: setTimeout(() => {
          const { delta } = syncQueue.current[entry.id];
          performSyncUpdate(entry, newAmount, delta);
          delete syncQueue.current[entry.id];
        }, 2000)
      };
    }
  };

  if (authLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-black text-accent">
        <div className="flex flex-col items-center gap-4">
            <Loader2 className="w-12 h-12 animate-spin text-accent" />
            <div className="font-mono text-sm animate-pulse uppercase tracking-[0.2em] text-accent">Matrix_Link_Establishing...</div>
        </div>
      </div>
    );
  }

  if (!user) {
    if (!showAuth) return <><HomePage onStart={() => setShowAuth(true)} isDark={true} toggleTheme={() => {}} /><AmbientSound /></>;
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-4 relative overflow-hidden bg-black text-white">
        <CyberBackground />
        <AmbientSound />
        <button onClick={() => setShowAuth(false)} className="absolute top-6 left-6 z-50 text-gray-500 hover:text-accent flex items-center gap-2 font-mono text-xs transition-colors">
          <ArrowLeft className="w-4 h-4" /> <span>ABORT_SEQUENCE</span>
        </button>
        <CyberCard className="w-full max-w-md animate-slide-up">
          <div className="p-8">
            <div className="text-center mb-10">
              <div className="flex justify-center mb-6 relative">
                 <div className="absolute inset-0 bg-accent/20 blur-2xl rounded-full" />
                 <Logo className="w-24 h-24 relative z-10 drop-shadow-[0_0_10px_var(--accent-dim)] animate-pulse" />
              </div>
              <h1 className="text-3xl font-black text-white tracking-tighter mb-1"><GlitchText>ACCESS_CONTROL</GlitchText></h1>
              <p className="text-accent font-mono text-[10px] tracking-[0.2em] uppercase">Verify Identity to Proceed</p>
            </div>
            <form onSubmit={handleAuth} className="space-y-6">
              <CyberInput label="User ID / Email" type="email" required value={email} onChange={(e) => setEmail(e.target.value)} placeholder="runner@net.city" />
              <CyberInput label="Access Key / Password" type="password" required value={password} onChange={(e) => setPassword(e.target.value)} placeholder="••••••••" />
              {error && <div className="p-3 border border-cyber-pink bg-cyber-pink/10 text-cyber-pink text-xs font-mono flex items-center gap-2"><Wifi className="w-4 h-4"/> ERROR: {error}</div>}
              <CyberButton type="submit" primary className="w-full" disabled={formLoading}>
                {formLoading ? <div className="flex items-center justify-center gap-2"><Loader2 className="w-5 h-5 animate-spin" /><span>PROCESSING...</span></div> : (isSignUp ? 'Initialize_Account' : 'Jack_In')}
              </CyberButton>
            </form>
            <div className="mt-8 relative"><div className="absolute inset-0 flex items-center"><div className="w-full border-t border-gray-800"></div></div><div className="relative flex justify-center text-xs"><span className="bg-black px-2 text-gray-600 font-mono">ALTERNATE_UPLINK</span></div></div>
            <button type="button" onClick={handleGoogleLogin} disabled={formLoading} className="mt-6 w-full py-3 bg-white hover:bg-gray-100 text-black font-sans font-bold text-sm transition-all flex items-center justify-center gap-3 uppercase tracking-wider group shadow-[0_0_15px_rgba(255,255,255,0.1)] hover:shadow-[0_0_20px_rgba(255,255,255,0.3)]">
              <svg className="w-5 h-5" viewBox="0 0 24 24">
                <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4" />
                <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853" />
                <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05" />
                <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335" />
              </svg>
              <span>Sign In with Google</span>
            </button>
            <div className="mt-8 text-center">
              <button onClick={() => setIsSignUp(!isSignUp)} className="text-xs text-accent hover:text-white font-mono hover:underline decoration-accent underline-offset-4">
                {isSignUp ? "HAS_ACCOUNT? EXECUTE LOGIN" : "NO_DATA? CREATE NEW RECORD"}
              </button>
            </div>
          </div>
        </CyberCard>
      </div>
    );
  }

  const stats = calculateStats(history, watchlist);

  return (
    <div className="min-h-screen relative pb-20 font-sans selection:bg-cyber-pink selection:text-white bg-[var(--bg-color)] text-[var(--text-color)] transition-colors duration-500">
      <CyberBackground />
      <AmbientSound />

      <header className="sticky top-0 z-40 bg-[var(--bg-color)]/80 backdrop-blur-md border-b border-[var(--border-color)]">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-3 group">
            <Logo className="w-10 h-10 hover:scale-110 transition-transform duration-300" />
            <span className="font-mono font-bold text-xl tracking-tighter text-[var(--text-color)] group-hover:text-accent transition-colors">ANI<span className="text-accent">TRACK</span></span>

            <button onClick={syncData} className="ml-4 flex items-center gap-2 border-l border-gray-800 pl-4 h-8 group/sync">
               {hasPendingWrites || isSyncing || pendingOpsCount > 0 ? (
                 <div className="flex items-center gap-2 text-amber-500 animate-pulse">
                    <CloudUpload className="w-3.5 h-3.5 animate-bounce" />
                    <span className="text-[10px] font-mono font-bold hidden md:inline">
                      {pendingOpsCount > 0 ? `${pendingOpsCount} PENDING_OPS` : 'UPLINKING...'}
                    </span>
                 </div>
               ) : (
                 <div className="flex items-center gap-2 text-accent">
                    <Cloud className="w-4 h-4 group-hover/sync:scale-110 transition-transform" />
                    <span className="text-[10px] font-mono font-bold hidden md:inline">SYNCHRONIZED</span>
                 </div>
               )}
            </button>
          </div>

          <div className="flex items-center gap-6">
            <div className="hidden lg:flex flex-col items-end cursor-default font-mono border-r border-gray-800 pr-6 mr-2">
                <span className="text-xs font-bold text-accent leading-none mb-1 flex items-center gap-2">
                   <UserCheck className="w-3 h-3 text-accent" /> {user.displayName || 'ANON_RUNNER'}
                </span>
                <span className="text-[9px] text-gray-500 uppercase tracking-widest">{lastSyncTime ? `SYNC_OK: ${lastSyncTime.toLocaleTimeString()}` : 'INITIALIZING...'}</span>
            </div>
            <div className="flex items-center gap-4">
                <button onClick={() => setShowProfile(true)} className="w-10 h-10 border border-gray-700 hover:border-accent transition-all flex items-center justify-center overflow-hidden bg-black relative">
                     {user.photoURL ? <img src={user.photoURL} alt="User" className="w-full h-full object-cover opacity-80" /> : <Ghost className="w-5 h-5 text-gray-500" />}
                     <div className="absolute top-0 right-0 w-2 h-2 bg-accent border border-black rounded-full" />
                </button>
                <button onClick={handleLogout} className="p-2 text-gray-600 hover:text-red-500 transition-colors"><LogOut className="w-5 h-5" /></button>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 pt-10 relative z-10">
        {(error || isOffline) && (
          <div className={`mb-8 p-4 border flex items-center justify-between gap-4 animate-fade-in ${isOffline ? 'bg-amber-900/20 border-amber-500 text-amber-500' : 'bg-cyber-pink/10 border-cyber-pink text-cyber-pink'}`}>
            <div className="flex items-center gap-3">
               {isOffline ? <CloudOff className="w-6 h-6" /> : <AlertTriangle className="w-6 h-6" />}
               <div><h3 className="font-bold font-mono tracking-wider">{isOffline ? 'OFFLINE_MODE' : 'SYNC_PROTOCOL_ERROR'}</h3><p className="text-xs font-mono opacity-80">{isOffline ? 'LOCAL_CACHE_ONLY. RECONNECT TO UPLOAD.' : error}</p></div>
            </div>
            <button onClick={() => setError('')} className="p-2 hover:bg-white/10 rounded"><X className="w-5 h-5" /></button>
          </div>
        )}

        <section className="mb-16 animate-fade-in">
          <div className="flex items-end justify-between mb-8 border-b border-[var(--border-color)] pb-4">
             <div><h2 className="text-2xl font-black text-[var(--text-color)] uppercase tracking-tight mb-1">Data Overview</h2><div className="text-[10px] font-mono text-gray-500">NEURAL_DASHBOARD</div></div>
             <button onClick={() => setShowHistory(true)} className="flex items-center gap-2 px-4 py-2 bg-white/5 border border-[var(--border-color)] hover:border-accent text-gray-400 text-xs font-mono transition-all uppercase tracking-wider">
               <History className="w-3 h-3" /> View Logs
             </button>
          </div>
          <StatsBoard stats={stats} />
        </section>

        <section className="mb-20 flex flex-col items-center">
          <div className="w-full max-w-2xl text-center mb-8">
             <h2 className="text-xl font-bold text-[var(--text-color)] uppercase tracking-widest mb-2"><GlitchText>Database Entry</GlitchText></h2>
             <div className="h-0.5 w-24 bg-accent mx-auto" />
          </div>
          <AnimeSearch onAddAnime={addAnimeToLibrary} watchlist={watchlist} />
        </section>

        <section>
          <div className="flex flex-col sm:flex-row items-end justify-between mb-8 gap-4 border-b border-[var(--border-color)] pb-4">
            <div className="flex items-center gap-4">
                <h2 className="text-3xl font-black text-[var(--text-color)] flex items-center gap-3 uppercase">MEMORY BANK <span className="text-lg font-mono font-normal text-accent border border-accent px-2 py-0.5">{watchlist.length}</span></h2>
                <button onClick={syncData} disabled={isSyncing} className={`p-2 border border-gray-800 text-gray-600 hover:text-accent hover:border-accent transition-all rounded-full ${isSyncing ? 'animate-spin' : ''}`}><RefreshCw className="w-4 h-4" /></button>
            </div>
            <div className="flex items-center gap-3">
              <span className="text-[10px] font-mono text-gray-500 uppercase">Sort:</span>
              <div className="flex gap-1">
                <button onClick={() => setSortType('updated')} className={`px-3 py-1 text-[10px] font-mono border ${sortType === 'updated' ? 'bg-accent/20 border-accent text-accent' : 'border-gray-800 text-gray-500 hover:border-gray-600'}`}>Recent</button>
                <button onClick={() => setSortType('title')} className={`px-3 py-1 text-[10px] font-mono border ${sortType === 'title' ? 'bg-accent/20 border-accent text-accent' : 'border-gray-800 text-gray-500 hover:border-gray-600'}`}>Alpha</button>
              </div>
            </div>
          </div>

          {watchlist.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-24 border border-dashed border-gray-800 bg-white/5">
              <Ghost className="w-16 h-16 text-gray-800 mb-4" />
              <p className="font-mono text-gray-500 text-lg uppercase">Memory Void</p>
              <p className="font-mono text-gray-700 text-[10px] mt-2 tracking-widest uppercase">Search to populate</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 sm:gap-6 lg:gap-8">
              {sortedWatchlist.map((entry) => (
                <AnimeCard 
                  key={entry.id} 
                  entry={entry} 
                  onUpdateEpisodes={updateEpisodesOptimistic} 
                  onRemove={(id) => {
                    if (window.confirm("WARNING: Purge record?")) {
                      db.collection('users').doc(user.uid).collection('watchlist').doc(id).delete();
                    }
                  }} 
                />
              ))}
            </div>
          )}
        </section>
      </main>

      {showProfile && user && <UserProfile user={user} stats={stats} animeCount={watchlist.length} themeSettings={themeSettings} onClose={() => setShowProfile(false)} />}
      {showHistory && <HistoryModal history={history} watchlist={watchlist} onClose={() => setShowHistory(false)} onUpdate={async (id, data) => {
        await db.collection('users').doc(user.uid).collection('history').doc(id).update(data);
      }} onDelete={async (id) => {
        await db.collection('users').doc(user.uid).collection('history').doc(id).delete();
      }} />}
    </div>
  );
};

export default App;

export interface Anime {
  mal_id: number;
  title: string;
  images: {
    jpg: {
      large_image_url: string;
      image_url: string;
    };
  };
  episodes: number | null;
  genres: { name: string }[];
  score?: number;
  synopsis?: string;
}

export interface ThemeSettings {
  mode: 'dark' | 'light';
  accentColor: string;
  accentName: string;
}

export interface WatchListEntry {
  id: string; // Firestore ID
  animeId: number;
  title: string;
  imageUrl: string;
  totalEpisodes: number | null;
  watchedEpisodes: number;
  genres: string[];
  updatedAt: string; // ISO String
  pending?: boolean; // True if data has not yet synced to the cloud
  score?: number;
  synopsis?: string;
}

export interface WatchHistoryItem {
  id?: string;
  animeId: number;
  animeTitle?: string;
  episodesDelta: number;
  timestamp: string; // ISO String
}

export interface UserStats {
  todayMinutes: number;
  monthMinutes: number;
  yearMinutes: number;
  lifetimeMinutes: number;
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import firebase from 'firebase/compat/app';
import { auth, db, googleProvider } from './firebase';
import { Anime, WatchListEntry, WatchHistoryItem, ThemeSettings } from './types';
import { calculateStats } from './services/statsService';
import { AnimeSearch } from './components/AnimeSearch';
import { AnimeCard } from './components/AnimeCard';
import { StatsBoard } from './components/StatsBoard';
import { UserProfile } from './components/UserProfile';
import { HistoryModal } from './components/HistoryModal';
import { HomePage } from './components/HomePage';
import { CyberBackground, CyberButton, CyberInput, CyberCard, GlitchText } from './components/CyberUI';
import { Logo } from './components/Logo';
import { AmbientSound } from './components/AmbientSound';
import { Loader2, LogOut, History, ArrowLeft, Ghost, Wifi, AlertTriangle, X, CloudOff, Cloud, RefreshCw, UserCheck, Zap, Palette, UploadCloud } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<firebase.User | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [watchlist, setWatchlist] = useState<WatchListEntry[]>([]);
  const [history, setHistory] = useState<WatchHistoryItem[]>([]);
  const [sortType, setSortType] = useState<'updated' | 'title'>('updated');
  const [showProfile, setShowProfile] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [isOffline, setIsOffline] = useState(!navigator.onLine);
  const [hasPendingWrites, setHasPendingWrites] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSyncTime, setLastSyncTime] = useState<Date | null>(null);
  const [themeSettings, setThemeSettings] = useState<ThemeSettings | null>(null);
  const [pendingOpsCount, setPendingOpsCount] = useState(0);

  // Auth Form State
  const [showAuth, setShowAuth] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isSignUp, setIsSignUp] = useState(false);
  const [error, setError] = useState('');
  const [formLoading, setFormLoading] = useState(false);

  // Debounce and Sync Refs
  const syncQueue = useRef<Record<string, { timer: ReturnType<typeof setTimeout>, delta: number, initialWatched: number }>>({});

  // Apply theme to document
  useEffect(() => {
    const root = document.documentElement;
    if (themeSettings) {
      root.style.setProperty('--accent-color', themeSettings.accentColor);
      try {
        const hex = themeSettings.accentColor.replace('#', '');
        const r = parseInt(hex.substring(0, 2), 16);
        const g = parseInt(hex.substring(2, 4), 16);
        const b = parseInt(hex.substring(4, 6), 16);
        root.style.setProperty('--accent-dim', `rgba(${r}, ${g}, ${b}, 0.2)`);
      } catch (e) {
        root.style.setProperty('--accent-dim', `rgba(0, 255, 159, 0.2)`);
      }

      if (themeSettings.mode === 'light') {
        root.classList.add('light');
        root.classList.remove('dark');
      } else {
        root.classList.add('dark');
        root.classList.remove('light');
      }
    } else {
      root.classList.add('dark');
      root.classList.remove('light');
      root.style.setProperty('--accent-color', '#00ff9f');
      root.style.setProperty('--accent-dim', 'rgba(0, 255, 159, 0.2)');
    }
  }, [themeSettings]);

  // Network Listener
  useEffect(() => {
    const handleOnline = () => setIsOffline(false);
    const handleOffline = () => setIsOffline(true);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Auth Listener
  useEffect(() => {
    const unsubscribe = auth.onAuthStateChanged((currentUser) => {
      setUser(currentUser);
      setAuthLoading(false);
      if (currentUser) {
        setShowAuth(false);
      }
    });
    return () => unsubscribe();
  }, []);

  // Theme Listener
  useEffect(() => {
    if (!user) return;
    const unsub = db.collection('users').doc(user.uid).onSnapshot((doc) => {
      if (doc.exists) {
        const data = doc.data();
        if (data?.theme) {
          setThemeSettings(data.theme);
        }
      }
    });
    return () => unsub();
  }, [user]);

  const formatFirestoreDate = (val: any): string => {
    if (!val) return new Date().toISOString();
    if (typeof val.toDate === 'function') return val.toDate().toISOString();
    return val;
  };

  const syncData = async () => {
    if (!user) return;
    setIsSyncing(true);
    setError('');

    try {
      const watchlistRef = db.collection('users').doc(user.uid).collection('watchlist');
      const historyRef = db.collection('users').doc(user.uid).collection('history');

      const [wSnap, hSnap] = await Promise.all([
        watchlistRef.get({ source: 'server' }),
        historyRef.get({ source: 'server' })
      ]);

      const wList = wSnap.docs.map(doc => ({ 
        id: doc.id, 
        ...doc.data(),
        updatedAt: formatFirestoreDate(doc.get('updatedAt'))
      })) as WatchListEntry[];

      const hList = hSnap.docs.map(doc => ({ 
        id: doc.id, 
        ...doc.data(),
        timestamp: formatFirestoreDate(doc.get('timestamp'))
      })) as WatchHistoryItem[];

      setWatchlist(wList);
      setHistory(hList);
      setLastSyncTime(new Date());
    } catch (err: any) {
      setError("SYNC_LINK_TIMEOUT: Retrying with local cache.");
    } finally {
      setIsSyncing(false);
    }
  };

  useEffect(() => {
    if (!user) {
      setWatchlist([]);
      setHistory([]);
      return;
    }

    const userRef = db.collection('users').doc(user.uid);

    const unsubWatchlist = userRef.collection('watchlist').onSnapshot({ includeMetadataChanges: true }, (snapshot) => {
      const list = snapshot.docs.map(doc => {
        const data = doc.data();
        return {
          id: doc.id,
          ...data,
          updatedAt: formatFirestoreDate(data.updatedAt),
          pending: doc.metadata.hasPendingWrites
        };
      }) as WatchListEntry[];

      setWatchlist(list);
      setHasPendingWrites(snapshot.metadata.hasPendingWrites);
      if (!snapshot.metadata.hasPendingWrites) {
        setLastSyncTime(new Date());
      }
    });

    const unsubHistory = userRef.collection('history').onSnapshot((snapshot) => {
      const hist = snapshot.docs.map(doc => {
        const data = doc.data();
        return {
          id: doc.id,
          ...data,
          timestamp: formatFirestoreDate(data.timestamp)
        };
      }) as WatchHistoryItem[];
      setHistory(hist);
    });

    const unsubSync = db.onSnapshotsInSync(() => {
      setHasPendingWrites(false);
    });

    return () => {
      unsubWatchlist();
      unsubHistory();
      unsubSync();
    };
  }, [user]);

  const sortedWatchlist = useMemo(() => {
    const data = [...watchlist];
    if (sortType === 'updated') {
      return data.sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime());
    } else {
      return data.sort((a, b) => a.title.localeCompare(b.title));
    }
  }, [watchlist, sortType]);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setFormLoading(true);
    try {
      if (isSignUp) {
        await auth.createUserWithEmailAndPassword(email, password);
      } else {
        await auth.signInWithEmailAndPassword(email, password);
      }
    } catch (err: any) {
      setError(err.message.replace('Firebase: ', ''));
    } finally {
      setFormLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
    setError('');
    setFormLoading(true);
    try {
      await auth.signInWithPopup(googleProvider);
    } catch (err: any) {
      setError(err.message.replace('Firebase: ', ''));
      setFormLoading(false);
    }
  };

  const handleLogout = () => {
      setError('');
      auth.signOut();
  };

  const addAnimeToLibrary = async (anime: Anime, initialWatched: number) => {
    if (!user) return;

    // Optimistic UI for Adding
    const tempId = `temp-${Date.now()}`;
    const tempEntry: WatchListEntry = {
      id: tempId,
      animeId: anime.mal_id,
      title: anime.title,
      imageUrl: anime.images.jpg.large_image_url,
      totalEpisodes: anime.episodes,
      watchedEpisodes: initialWatched,
      genres: anime.genres.map(g => g.name),
      score: anime.score || null,
      synopsis: anime.synopsis || "",
      updatedAt: new Date().toISOString(),
      pending: true
    };

    setWatchlist(prev => [tempEntry, ...prev]);

    try {
        const batch = db.batch();
        const watchlistRef = db.collection('users').doc(user.uid).collection('watchlist').doc();

        batch.set(watchlistRef, {
          animeId: anime.mal_id,
          title: anime.title,
          imageUrl: anime.images.jpg.large_image_url,
          totalEpisodes: anime.episodes,
          watchedEpisodes: initialWatched,
          genres: anime.genres.map(g => g.name),
          score: anime.score || null,
          synopsis: anime.synopsis || "",
          updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });

        if (initialWatched > 0) {
            const historyRef = db.collection('users').doc(user.uid).collection('history').doc();
            batch.set(historyRef, {
                animeId: anime.mal_id,
                animeTitle: anime.title,
                episodesDelta: initialWatched,
                timestamp: firebase.firestore.FieldValue.serverTimestamp()
            });
        }

        await batch.commit();
    } catch (err: any) {
        setError(`WRITE_ERROR: ${err.message}`);
        // Revert optimistic add
        setWatchlist(prev => prev.filter(e => e.id !== tempId));
    }
  };

  const performSyncUpdate = async (entry: WatchListEntry, finalAmount: number, delta: number) => {
    if (!user) return;
    setPendingOpsCount(prev => Math.max(0, prev - 1));

    try {
        const batch = db.batch();
        const entryRef = db.collection('users').doc(user.uid).collection('watchlist').doc(entry.id);
        const historyRef = db.collection('users').doc(user.uid).collection('history').doc();

        batch.update(entryRef, {
          watchedEpisodes: finalAmount,
          updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });

        batch.set(historyRef, {
          animeId: entry.animeId,
          animeTitle: entry.title,
          episodesDelta: delta,
          timestamp: firebase.firestore.FieldValue.serverTimestamp()
        });

        await batch.commit();
    } catch (err: any) {
        setError(`DEBOUNCED_SYNC_ERROR: ${err.message}`);
    }
  };

  const updateEpisodesOptimistic = (entry: WatchListEntry, newAmount: number) => {
    if (!user) return;

    // 1. Update Application State Immediately (Optimistic)
    setWatchlist(prev => prev.map(e => e.id === entry.id ? { ...e, watchedEpisodes: newAmount, pending: true } : e));

    // 2. Debounce Cloud Sync
    if (syncQueue.current[entry.id]) {
      clearTimeout(syncQueue.current[entry.id].timer);
      const prevDelta = syncQueue.current[entry.id].delta;
      const initialWatched = syncQueue.current[entry.id].initialWatched;

      syncQueue.current[entry.id] = {
        initialWatched,
        delta: newAmount - initialWatched,
        timer: setTimeout(() => {
          const { delta } = syncQueue.current[entry.id];
          performSyncUpdate(entry, newAmount, delta);
          delete syncQueue.current[entry.id];
        }, 2000)
      };
    } else {
      setPendingOpsCount(prev => prev + 1);
      syncQueue.current[entry.id] = {
        initialWatched: entry.watchedEpisodes,
        delta: newAmount - entry.watchedEpisodes,
        timer: setTimeout(() => {
          const { delta } = syncQueue.current[entry.id];
          performSyncUpdate(entry, newAmount, delta);
          delete syncQueue.current[entry.id];
        }, 2000)
      };
    }
  };

  if (authLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-black text-accent">
        <div className="flex flex-col items-center gap-4">
            <Loader2 className="w-12 h-12 animate-spin text-accent" />
            <div className="font-mono text-sm animate-pulse uppercase tracking-[0.2em] text-accent">Matrix_Link_Establishing...</div>
        </div>
      </div>
    );
  }

  if (!user) {
    if (!showAuth) return <><HomePage onStart={() => setShowAuth(true)} isDark={true} toggleTheme={() => {}} /><AmbientSound /></>;
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-4 relative overflow-hidden bg-black text-white">
        <CyberBackground />
        <AmbientSound />
        <button onClick={() => setShowAuth(false)} className="absolute top-6 left-6 z-50 text-gray-500 hover:text-accent flex items-center gap-2 font-mono text-xs transition-colors">
          <ArrowLeft className="w-4 h-4" /> <span>ABORT_SEQUENCE</span>
        </button>
        <CyberCard className="w-full max-w-md animate-slide-up">
          <div className="p-8">
            <div className="text-center mb-10">
              <div className="flex justify-center mb-6 relative">
                 <div className="absolute inset-0 bg-accent/20 blur-2xl rounded-full" />
                 <Logo className="w-24 h-24 relative z-10 drop-shadow-[0_0_10px_var(--accent-dim)] animate-pulse" />
              </div>
              <h1 className="text-3xl font-black text-white tracking-tighter mb-1"><GlitchText>ACCESS_CONTROL</GlitchText></h1>
              <p className="text-accent font-mono text-[10px] tracking-[0.2em] uppercase">Verify Identity to Proceed</p>
            </div>
            <form onSubmit={handleAuth} className="space-y-6">
              <CyberInput label="User ID / Email" type="email" required value={email} onChange={(e) => setEmail(e.target.value)} placeholder="runner@net.city" />
              <CyberInput label="Access Key / Password" type="password" required value={password} onChange={(e) => setPassword(e.target.value)} placeholder="••••••••" />
              {error && <div className="p-3 border border-cyber-pink bg-cyber-pink/10 text-cyber-pink text-xs font-mono flex items-center gap-2"><Wifi className="w-4 h-4"/> ERROR: {error}</div>}
              <CyberButton type="submit" primary className="w-full" disabled={formLoading}>
                {formLoading ? <div className="flex items-center justify-center gap-2"><Loader2 className="w-5 h-5 animate-spin" /><span>PROCESSING...</span></div> : (isSignUp ? 'Initialize_Account' : 'Jack_In')}
              </CyberButton>
            </form>
            <div className="mt-8 relative"><div className="absolute inset-0 flex items-center"><div className="w-full border-t border-gray-800"></div></div><div className="relative flex justify-center text-xs"><span className="bg-black px-2 text-gray-600 font-mono">ALTERNATE_UPLINK</span></div></div>
            <button type="button" onClick={handleGoogleLogin} disabled={formLoading} className="mt-6 w-full py-3 bg-white hover:bg-gray-100 text-black font-sans font-bold text-sm transition-all flex items-center justify-center gap-3 uppercase tracking-wider group shadow-[0_0_15px_rgba(255,255,255,0.1)] hover:shadow-[0_0_20px_rgba(255,255,255,0.3)]">
              <svg className="w-5 h-5" viewBox="0 0 24 24">
                <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4" />
                <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853" />
                <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05" />
                <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335" />
              </svg>
              <span>Sign In with Google</span>
            </button>
            <div className="mt-8 text-center">
              <button onClick={() => setIsSignUp(!isSignUp)} className="text-xs text-accent hover:text-white font-mono hover:underline decoration-accent underline-offset-4">
                {isSignUp ? "HAS_ACCOUNT? EXECUTE LOGIN" : "NO_DATA? CREATE NEW RECORD"}
              </button>
            </div>
          </div>
        </CyberCard>
      </div>
    );
  }

  const stats = calculateStats(history, watchlist);

  return (
    <div className="min-h-screen relative pb-20 font-sans selection:bg-cyber-pink selection:text-white bg-[var(--bg-color)] text-[var(--text-color)] transition-colors duration-500">
      <CyberBackground />
      <AmbientSound />

      <header className="sticky top-0 z-40 bg-[var(--bg-color)]/80 backdrop-blur-md border-b border-[var(--border-color)]">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-3 group">
