  const getErrorConfig = (msg: string) => {
    if (msg.includes("Network:")) {
      return { 
        icon: WifiOff, 
        text: "OFFLINE_UPLINK", 
        subtext: "Check your neural connection settings.", 
        color: "text-amber-500", 
