                <button onClick={syncData} disabled={isSyncing} className={`p-2 border border-gray-800 text-gray-600 hover:text-accent hover:border-accent transition-all rounded-full ${isSyncing ? 'animate-spin' : ''}`} title="Verify Deep Cloud Sync"><RefreshCw className="w-4 h-4" /></button>
            </div>
            <div className="flex items-center gap-3">
              <span className="text-[10px] font-mono text-gray-500 uppercase">Filters:</span>
              <div className="flex gap-1">
                <button 
                  onClick={() => setFilterFavorites(!filterFavorites)} 
                  className={`px-3 py-1 text-[10px] font-mono border flex items-center gap-1.5 transition-all ${filterFavorites ? 'bg-yellow-400/20 border-yellow-400 text-yellow-400 shadow-[0_0_10px_rgba(250,204,21,0.2)]' : 'border-gray-800 text-gray-500 hover:border-gray-600'}`}
                >
                  <Star className={`w-3 h-3 ${filterFavorites ? 'fill-yellow-400' : ''}`} /> Favorites
                </button>
                <div className="w-px h-4 bg-gray-800 mx-1 self-center" />
                <button onClick={() => setSortType('updated')} className={`px-3 py-1 text-[10px] font-mono border ${sortType === 'updated' ? 'bg-accent/20 border-accent text-accent' : 'border-gray-800 text-gray-500 hover:border-gray-600'}`}>Recent</button>
                <button onClick={() => setSortType('title')} className={`px-3 py-1 text-[10px] font-mono border ${sortType === 'title' ? 'bg-accent/20 border-accent text-accent' : 'border-gray-800 text-gray-500 hover:border-gray-600'}`}>Alpha</button>
              </div>
            </div>
          </div>

          {sortedWatchlist.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-24 border border-dashed border-gray-800 bg-white/5">
              <Ghost className="w-16 h-16 text-gray-800 mb-4" />
              <p className="font-mono text-gray-500 text-lg uppercase">{filterFavorites ? 'No Favorites Found' : 'Memory Void'}</p>
              <p className="font-mono text-gray-700 text-[10px] mt-2 tracking-widest uppercase">{filterFavorites ? 'Mark records as favorite to see them here' : 'Search to populate'}</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 sm:gap-6 lg:gap-8">
              {sortedWatchlist.map((entry) => (
                <AnimeCard 
                  key={entry.id} 
                  entry={entry} 
                  onUpdateEpisodes={updateEpisodesOptimistic} 
                  onToggleFavorite={handleToggleFavorite}
                  onRemove={handleRemoveAnime} 
                />
              ))}
            </div>
          )}
        </section>
      </main>

      {showProfile && user && <UserProfile user={user} stats={stats} watchlist={watchlist} themeSettings={themeSettings} onClose={() => setShowProfile(false)} />}
      {showHistory && <HistoryModal history={history} watchlist={watchlist} onClose={() => setShowHistory(false)} onUpdate={async (id, data) => {
        await db.collection('users').doc(user.uid).collection('history').doc(id).update(data);
      }} onDelete={async (id) => {
        await db.collection('users').doc(user.uid).collection('history').doc(id).delete();
      }} />}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import firebase from 'firebase/compat/app';
import { auth, storage, db } from '../firebase';
import { UserStats, ThemeSettings, WatchListEntry } from '../types';
import { formatMinutes } from '../services/statsService';
import { X, User as UserIcon, Save, Key, AlertCircle, CheckCircle, Database, Camera, Loader2, Zap, ShieldCheck, Palette, Moon, Sun, Monitor, Paintbrush, FileDown, Share2, Upload, FileJson } from 'lucide-react';
import { CyberButton, CyberInput, CyberCard, GlitchText } from './CyberUI';

interface UserProfileProps {
  user: firebase.User;
  stats: UserStats;
  watchlist: WatchListEntry[];
  themeSettings: ThemeSettings | null;
  onClose: () => void;
}

const ACCENT_PRESETS = [
  { name: 'Emerald', color: '#00ff9f' },
  { name: 'Rose', color: '#ff0055' },
  { name: 'Cyan', color: '#00baee' },
  { name: 'Amethyst', color: '#bc13fe' },
  { name: 'Amber', color: '#ffb000' }
];

export const UserProfile: React.FC<UserProfileProps> = ({ user, stats, watchlist, themeSettings, onClose }) => {
  const [displayName, setDisplayName] = useState(user.displayName || '');
  const [loading, setLoading] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);

  const [currentMode, setCurrentMode] = useState<'dark' | 'light'>(themeSettings?.mode || 'dark');
  const [currentAccent, setCurrentAccent] = useState(themeSettings?.accentColor || '#00ff9f');

  useEffect(() => {
    if (themeSettings) {
      setCurrentMode(themeSettings.mode);
      setCurrentAccent(themeSettings.accentColor);
    }
  }, [themeSettings]);

  const handleUpdateProfile = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setMessage(null);
    try {
      await user.updateProfile({ displayName });
      setMessage({ type: 'success', text: 'IDENTITY_RECORD UPDATED' });
    } catch (error: any) {
      setMessage({ type: 'error', text: `SYNC_FAILED: ${error.message}` });
    } finally {
      setLoading(false);
    }
  };

  const handleSaveTheme = async (mode: 'dark' | 'light', colorObj: {name: string, color: string}) => {
    setLoading(true);
    try {
      await db.collection('users').doc(user.uid).set({
        theme: {
          mode,
          accentColor: colorObj.color,
          accentName: colorObj.name
        }
      }, { merge: true });
      setMessage({ type: 'success', text: 'NEURAL_THEME_LINKED' });
      setTimeout(() => setMessage(null), 3000);
    } catch (err: any) {
      setMessage({ type: 'error', text: `THEME_SYNC_FAILED: ${err.message}` });
    } finally {
      setLoading(false);
    }
  };

  const handlePasswordReset = async () => {
    if (!user.email) return;
    setLoading(true);
    setMessage(null);
    try {
        await auth.sendPasswordResetEmail(user.email);
        setMessage({ type: 'success', text: 'RESET_PROTOCOL INITIATED. CHECK INBOX.' });
    } catch (error: any) {
        setMessage({ type: 'error', text: error.message });
    } finally {
        setLoading(false);
    }
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!file.type.startsWith('image/')) {
        setMessage({ type: 'error', text: 'INVALID FORMAT. IMAGE REQUIRED.' });
        return;
    }

    if (file.size > 5 * 1024 * 1024) {
      setMessage({ type: 'error', text: 'PAYLOAD TOO LARGE. MAX 5MB.' });
      return;
    }

    setUploading(true);
    setMessage(null);

    const reader = new FileReader();
    reader.onload = async (event) => {
      const dataUrl = event.target?.result as string;
      if (!dataUrl) {
        setMessage({ type: 'error', text: 'READ_ERROR: FAILED TO PROCESS IMAGE.' });
        setUploading(false);
        return;
      }

      try {
          const fileExtension = file.name.split('.').pop() || 'jpg';
          const storagePath = `avatars/${user.uid}/${Date.now()}.${fileExtension}`;
          const storageRef = storage.ref().child(storagePath);
          const snapshot = await storageRef.putString(dataUrl, 'data_url');
          const photoURL = await snapshot.ref.getDownloadURL();
          await user.updateProfile({ photoURL });
          await user.reload(); 
          setMessage({ type: 'success', text: 'AVATAR SYNCED TO SECURE_STORAGE.' });
      } catch (error: any) {
          setMessage({ type: 'error', text: `UPLINK_FAILED: ${error.message}` });
      } finally {
          setUploading(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const exportToCSV = () => {
    if (watchlist.length === 0) {
      setMessage({ type: 'error', text: 'EXPORT_FAILED: MEMORY BANK IS EMPTY.' });
      return;
    }

    // Comprehensive Headers for full restore capability
    const headers = [
        "MAL_ID", 
        "Title", 
        "ImageURL", 
        "Episodes Watched", 
        "Total Episodes", 
        "Genres", 
        "Score", 
        "Synopsis", 
        "IsFavorite"
    ];

    const rows = watchlist.map(entry => {
      const fields = [
        entry.animeId,
        `"${entry.title.replace(/"/g, '""')}"`,
        `"${entry.imageUrl}"`,
        entry.watchedEpisodes,
        entry.totalEpisodes || "",
        `"${entry.genres.join(';').replace(/"/g, '""')}"`,
        entry.score || "",
        `"${(entry.synopsis || "").replace(/"/g, '""')}"`,
        entry.isFavorite ? "TRUE" : "FALSE"
      ];
      return fields.join(",");
    });

    const csvContent = "\uFEFF" + headers.join(",") + "\n" + rows.join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `anitrack_export_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);

    setMessage({ type: 'success', text: 'DATA_EXPORT_SUCCESSFUL: ARCHIVE CREATED' });
    setTimeout(() => setMessage(null), 3000);
  };

  const handleImportCSV = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!file.name.endsWith('.csv')) {
        setMessage({ type: 'error', text: 'INVALID_PROTOCOL: ONLY .CSV FILES SUPPORTED' });
        return;
    }

    setLoading(true);
    setMessage(null);

    const reader = new FileReader();
    reader.onload = async (event) => {
        const text = event.target?.result as string;
        if (!text) return;

        try {
            const lines = text.split(/\r?\n/);
            if (lines.length < 2) throw new Error("FILE_EMPTY");

            const headers = lines[0].toLowerCase();
            if (!headers.includes("mal_id") || !headers.includes("title")) {
                throw new Error("INVALID_HEADER: CORRUPTED DATA TEMPLATE");
            }

            const batch = db.batch();
            const watchlistRef = db.collection('users').doc(user.uid).collection('watchlist');
            const historyRef = db.collection('users').doc(user.uid).collection('history');

            let importCount = 0;

            // Simple CSV parser for quoted strings
            const parseCSVLine = (line: string) => {
                const result = [];
                let current = '';
                let inQuotes = false;
                for (let i = 0; i < line.length; i++) {
                    const char = line[i];
                    if (char === '"' && line[i+1] === '"') {
                        current += '"';
                        i++;
                    } else if (char === '"') {
                        inQuotes = !inQuotes;
                    } else if (char === ',' && !inQuotes) {
                        result.push(current);
                        current = '';
                    } else {
                        current += char;
                    }
                }
                result.push(current);
                return result;
            };

            for (let i = 1; i < lines.length; i++) {
                const line = lines[i].trim();
                if (!line) continue;

                const values = parseCSVLine(line);
                if (values.length < 5) continue;

                const [mal_id, title, imageUrl, watched, total, genres, score, synopsis, isFav] = values;

                // Check if already exists in local memory to avoid duplicates
                const animeId = parseInt(mal_id);
                if (watchlist.some(w => w.animeId === animeId)) continue;

                const docRef = watchlistRef.doc();
                const watchedNum = parseInt(watched) || 0;

                batch.set(docRef, {
                    animeId: animeId,
                    title: title,
                    imageUrl: imageUrl || "",
                    watchedEpisodes: watchedNum,
                    totalEpisodes: parseInt(total) || null,
                    genres: genres ? genres.split(';') : [],
                    score: parseFloat(score) || null,
                    synopsis: synopsis || null,
                    isFavorite: isFav === "TRUE",
                    updatedAt: firebase.firestore.FieldValue.serverTimestamp()
                });

                if (watchedNum > 0) {
                    const hRef = historyRef.doc();
                    batch.set(hRef, {
                        animeId: animeId,
                        animeTitle: title,
                        episodesDelta: watchedNum,
                        timestamp: firebase.firestore.FieldValue.serverTimestamp()
                    });
                }

                importCount++;
                if (importCount >= 400) break; // Firestore batch limit safeguard
            }

            if (importCount > 0) {
                await batch.commit();
                setMessage({ type: 'success', text: `INJECTION_COMPLETE: ${importCount} RECORDS LINKED` });
            } else {
                setMessage({ type: 'error', text: "NO_NEW_DATA: ALL RECORDS ALREADY SYNCED" });
            }

        } catch (err: any) {
            setMessage({ type: 'error', text: `INJECTION_FAILED: ${err.message}` });
